-- PostgreSQL dump of Harry Potter API database
-- Translated from MySQL to PostgreSQL
-- Original: MySQL 8.0.33
-- Converted: 2026-03-21

-- Create the database (Run this first, then connect to it)
-- CREATE DATABASE api_harry_potter;
-- \c api_harry_potter;

-- Set encoding to UTF-8
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SET TIME ZONE 'UTC';

-- Drop existing tables if they exist
DROP TABLE IF EXISTS wizard CASCADE;
DROP TABLE IF EXISTS object CASCADE;
DROP TABLE IF EXISTS creatures CASCADE;
DROP TABLE IF EXISTS creature_tag CASCADE;

-- Table structure for table creature_tag
CREATE TABLE creature_tag (
    id INTEGER PRIMARY KEY,
    name VARCHAR(45),
    resume TEXT,
    phrase TEXT,
    life TEXT,
    picture VARCHAR(100),
    creatures_tags INTEGER
);

-- Dumping data for table creature_tag


-- Table structure for table creatures
DROP TABLE IF EXISTS creatures CASCADE;

CREATE TABLE creatures (
                           id INTEGER PRIMARY KEY,
                           raze VARCHAR(100) DEFAULT NULL,
                           picture VARCHAR(100) DEFAULT NULL,
                           phrase TEXT,
                           resume TEXT,
                           danger VARCHAR(20) NOT NULL,
                           classification VARCHAR(45) DEFAULT NULL
);

-- Dumping data for table creatures


-- Drop table if it already exists to avoid conflicts
DROP TABLE IF EXISTS object CASCADE;

-- Create the object table with PostgreSQL data types
CREATE TABLE object (
                        id INTEGER PRIMARY KEY,
                        name VARCHAR(45) DEFAULT NULL,
                        info TEXT,
                        picture VARCHAR(100) DEFAULT NULL,
                        is_horocruxe SMALLINT DEFAULT NULL,
                        is_hollow SMALLINT DEFAULT NULL,
                        is_wander SMALLINT DEFAULT NULL,
                        is_other SMALLINT DEFAULT NULL,
                        is_quiddich SMALLINT DEFAULT NULL
);

-- Insert all magical objects data


-- Table structure for table wizard
DROP TABLE IF EXISTS wizard CASCADE;

CREATE TABLE wizard (
                        id SERIAL PRIMARY KEY,
                        name VARCHAR(100) DEFAULT NULL,
                        familyname VARCHAR(100) DEFAULT NULL,
                        age INTEGER DEFAULT NULL,
                        picture VARCHAR(100) DEFAULT NULL,
                        rol VARCHAR(100) DEFAULT NULL,
                        actor VARCHAR(100) DEFAULT NULL,
                        bibliography TEXT,
                        facemember VARCHAR(100) DEFAULT NULL,
                        housename VARCHAR(100) DEFAULT NULL,
                        color VARCHAR(100) DEFAULT NULL,
                        blood VARCHAR(45) DEFAULT NULL,
                        patronus VARCHAR(45) DEFAULT NULL,
                        wander_info TEXT,
                        animals_fantastics VARCHAR(255) DEFAULT NULL,
                        mortifago SMALLINT DEFAULT NULL,
                        teacher SMALLINT DEFAULT NULL,
                        student SMALLINT DEFAULT NULL,
                        others SMALLINT DEFAULT NULL,
                        wizards_objects INTEGER DEFAULT NULL,
                        wizards_wanders INTEGER DEFAULT NULL
);

