INSERT INTO creature_tag VALUES
                             (2,'Hedwig','Hedwig era la lechuza y compañera mágica de Harry Potter. Fue un regalo por el undécimo cumpleaños de Harry hecho por Rubeus Hagrid en 1991, quien la compró en el Emporio de la Lechuza.\nAdemás de entregar el correo - un oficio típico para las lechuzas y búhos - Hedwig fue una importante compañera para Harry cuando éste entró en el mundo mágico. Ella continuó siendo una de sus mejores amigos durante toda su vida, acompañándolo tanto en el mundo mágico como en el mundo muggle. Demostrando su lealtad hacia Harry, murió en la Batalla de los Siete Potters durante el apogeo de la Segunda Guerra Mágica.','¡No! ¡Hedwig! ¡No! ¡NOOO! ¡Hedwig! ¡Hedwig! -Harry Potter-',' (nac. 1991 - muer. 27 de julio de 1997)','../../../assets/img/criatures/tags/hedwig.jpg',2),
                             (3,'Basilisco Slytherin','El Basilisco de Salazar Slytherin fue un Basilisco que cuidó la Cámara de los Secretos de Salazar Slytherin durante más de 1000 años. Tuvo un feroz enfrentamiento con Harry Potter, quien termino con su vida con la espada de Godric Gryffindor.','"Ven... ven a mí... déjame rasgarte... déjame despedazarte... déjame matarte."','(naci. alrededor del año 980 - muer. 29 de mayo de 1993)','../../../assets/img/criatures/tags/basilisco-salazar.jpg',3),
                             (4,'Firenze','El Profesor Firenze era un centauro, que forma parte de la Colonia de centauros del Bosque Prohibido, y un profesor de adivinación en el Colegio Hogwarts de Magia y Hechicería a partir de 1996 - hasta 1998.\nAntes de algún momento de marzo de 1996, vivió con la colonia en el Bosque Prohibido, en las fronteras de Hogwarts en Escocia. En 1992, Firenze salvó a Harry Potter en el bosque de Quirinus Quirrell, quien estaba poseído por Lord Voldemort, asustando a Quirrell y llevando a Harry en su espalda a un lugar seguro. A pesar de su heroicidad, su rebaño vio esto como un acto deshonroso, ya que se consideraban demasiado grandes para ser montados por humanos.\nAproximadamente cuatro años después, en marzo de 1996, Albus Dumbledore, Director de Hogwarts, lo contrató para enseñar Adivinación en lugar de Sybill Trelawney, después de que Dolores Umbridge la despidiera. Pero una vez más, los otros centauros vieron esto como una servidumbre, y su colonia lo atacó y lo desterró. Lo habrían matado si no fuera por la intervención de Rubeus Hagrid.\nDespués de que Dumbledore fuera reinstalado como director, Trelawney fue devuelta a su salón de clases. Sin embargo, dado que Firenze todavía estaba alejado de su colonia, Dumbledore les permitió a ambos continuar enseñando, aunque Trelawney se sentía incómoda al compartir sus clases con un centauro.\nCuando Firenze resultó herido luchando en la Batalla de Hogwarts, regresó a su colonia más tarde cuando los otros centauros habían llegado a la opinión de que sus inclinaciones pro-humanas no eran tan vergonzosas.','"Aquí es donde te dejo. Ya estás a salvo. Buena suerte, Harry Potter. Los planetas ya se han leído antes equivocadamente, hasta por centauros. Espero que ésta sea una de esas veces."',NULL,'../../../assets/img/criatures/tags/firenze.jpg',6),
                             (5,'Fawkes','Fawkes era un fénix macho muy inteligente y el compañero y defensor animal de Albus Dumbledore. Se desconoce cuánto tiempo estuvo Fawkes al servicio de Dumbledore. Había sido leal a Dumbledore durante muchos años antes de la muerte del director en 1997.\nFawkes fue fundamental para ayudar a Harry Potter a derrotar al basilisco de Salazar Slytherin en 1993. Sus lágrimas (que poseían propiedades curativas, como las de su especie) salvaron la vida de Harry después de que su brazo fuera perforado por el colmillo del basilisco y su veneno. En 1996, Fawkes acudió en ayuda de Dumbledore para luchar contra Lord Voldemort durante la Batalla del Departamento de Misterios.\nDespués de la muerte de Dumbledore, Fawkes cantó su lamento sobre los terrenos del Colegio Hogwarts de Magia y Hechicería, y luego se fue y se fue volando, para no ser visto nunca más. Las plumas de su cola eran los núcleos de las dos varitas gemelas que sostenían Lord Voldemort y Harry Potter.','"Profesor, su pájaro…, no pude hacer nada…, acaba de arder…" -- "Ya era hora. Hace días que tenía un aspecto horroroso. Yo le decía que se diera prisa." ','Inmortal','../../../assets/img/criatures/tags/fawkes.jpg',14),
                             (6,'Buckbeak','Buckbeak, luego renombrado Witherwings, es un hipogrifo. Vivió con Rubeus Hagrid durante el tercer año de Harry Potter en Hogwarts, junto con algunos otros hipogrifos. Más tarde fue condenado injustamente a muerte cuando atacó a Draco Malfoy después de ser insultado y provocado.La sentencia de muerte de Buckbeak fue entregada por la Comisión para las Criaturas Peligrosas. Muchos de los miembros de esta comisión habían sido amenazados por el padre de Draco, Lucius Malfoy, para que votara a favor de ese veredicto.\nCon la ayuda de Harry Potter, Hermione Granger y su giratiempo, Buckbeak escapó de la ejecución en 1994 y estuvo bajo el cuidado de Sirius Black.Sirius mantuvo a Buckbeak con él mientras huía durante el año escolar 1994–1995, y más tarde lo mantuvo en el dormitorio de su madre mientras estaba escondido en el Número 12 de Grimmauld Place.\nDespués de la muerte de Sirius, Buckbeak llegó a ser propiedad de Harry Potter a través del testamento de Sirius, aunque Harry le permitió vivir con Hagrid. Participó en dos batallas de la Segunda Guerra Mágica, en particular la Batalla de Hogwarts.También mostró gran afecto y lealtad hacia Harry, defendiéndolo cuando estaba en peligro.','"Buckbeak era un buen hipogrifo, siempre limpiaba sus plumas."','naci.1993 - muer. fecha desconocida','../../../assets/img/criatures/tags/buckbeak.jpg',16),
                             (7,'Nagini','Nagini fue una humana maledictus con una maldición sanguínea que terminaría convirtiéndole en una serpiente gigante. Posiblemente originaria de Indonesia,[2][3] en 1927 fue artista en el Circo Arcanus, donde conoció a Credence Barebone y tenía la capacidad de transformarse a voluntad. Alrededor del año 1994, Nagini se quedó aparentemente atrapada en su forma de serpiente y más tarde comenzó a ser pertenencia de Lord Voldemort, con el que tuvo un vínculo especial debido en gran parte a convertirse en un Horrocrux, después de que su maestro había matado Bertha Jorkins en 1994.\n\nDespués de la caída inicial de Voldemort, usó el veneno de Nagini como uno de los ingredientes de una poción para recuperar su fuerza, lo que finalmente lo llevó a renacer en 1995. Más tarde, ese mismo año, atacó a Arthur Weasley, pero él logró sobrevivir. Durante la Segunda Guerra Mágica, tuvo que ser destruida para que Voldemort finalmente fuera derrotado. Nagini fue asesinada por Neville Longbottom con la espada de Godric Gryffindor en 1998 y fue el último Horrocrux en ser destruido después de la diadema de Rowena Ravenclaw.','"Vivía cautiva en la selva de Indonesia y es portadora de una maldición sanguínea. Estos seres inferiores están destinados a transformarse en bestias a lo largo de toda su vida[...] Con el tiempo, ya no podrá recuperar su forma humana y quedará atrapada para siempre en el cuerpo de una serpiente."','naci. antes de 1920 - muer. 2 de mayo de 1998','../../../assets/img/criatures/tags/nagini.jpg',40),
                             (8,'Pickett','Pickett era un bowtruckle que tenía Newton Scamander como mascota. A pesar que él tenía al menos seis bowtruckles (Pickett, Titus, Poppy, Marlow, Finn y Tom), Newt tenía un cariño especial con Pickett y lo mantenía siempre en el bolsillo superior de su abrigo, primero porque Pickett tenía frío y necesitaba calor corporal, y también porque tenía ciertos problemas de apego.\n\nEn 1926, acompañó a Newt en su viaje a Nueva York, manteniéndose en su bolsillo superior. Estuvo presente cuando el escarbato escapó de la maleta en el Banco Nacional Steen y cuando Porpentina Goldstein llevó a Newt al Magicongreso Único de la Sociedad Americana.\n\nPickett seguía en el bolsillo de Newt cuando Gellert Grindelwald, bajo la apariencia de Percival Graves, sentenció a su dueño y a Tina a muerte. Como los bowtruckles son capaces de abrir cerraduras, desencadenó a Newt de sus esposas para escapar junto con Tina de la celda de la muerte.\n\nMás tarde, cuando Newt se reunió con el duende gángster Gnarlak, Newt le ofreció a Pickett al duende para poder conseguir información sobre las últimas criaturas escapadas. Gnarlak había tendido una trampa y los entregó al MACUSA. Mientras intentaban escapar, Jacob Kowalski golpeó a Gnarlak permitiendo que Newt pudiera rescatar su bowtruckle. Luego de ésto, Pickett se mostró malhumorado por haber sido entregado y le hace una pedorreta a Newt.\n\nEn 1927, Pickett estuvo presente mientras Newt esperaba un interrogatorio en el Ministerio británico de magia sobre su prohibición de viajar internacionalmente.\n\nPickett también acompañó a Newt en su viaje a París. Cuando Newt y Jacob Kowalski encontraron a Tina encarcelada por Yusuf Kama en su escondite en las alcantarillas de París, también fueron encarcelados por él. Cuando Yusuf se desmayó debido a un parásito de dragón de agua en su ojo, Pickett abrió la cerradura de la puerta y los ayudó a salir de la habitación.\n\nPickett luego se escapó del bolsillo de Newt e hizo que Leta encontrara a Newt y Tina en la Sala de archivos del Ministerio francés de la magia.','"Pickett tiene problemas de apego, y Newt sabe que no debe tener preferencias con el resto de animales, pero le tiene mucho cariño, y de hecho, le deja hospedarse en su bolsillo" -Newt Scamander-','Desconocida','../../../assets/img/criatures/tags/picket.jpg',25),
                             (9,'Fang','Fang es un perro jabalinero de gran tamaño, y una de las mascotas de Rubeus Hagrid. Él es un gran perro que acompaña a Hagrid a muchos lugares, incluyendo el Bosque Prohibido, y vive en la cabaña de Hagrid como su mascota.','"Fuera del camino, Fang ... Fuera del camino, perro dormilón ..." -Rubeus Hagrid-','Desconocida','../../../assets/img/criatures/tags/fang.jpg',39),
                             (10,'Fluffy','Fluffy fue criado por Rubeus Hagrid, el guardabosques de Hogwarts. Albus Dumbledore decidió colocar a Fluffy en una habitación en la que custodiaba una trampilla. Dicha trampilla es la entrada a una serie de pasadizos que hay antes de encontrar la Piedra Filosofal. El profesor Quirrell (o Voldemort) coincidió con Hagrid en un bar, y perdió con él, a propósito, un huevo de dragón (el pequeño Norberto), dándole de beber a Hagrid para que se le escapara el punto débil de Fluffy, que es la música. De modo que Quirrell encantó un arpa para dormirlo y entrar en busca de la Piedra Filosofal.','"Incluso una bestia grande y feroz como Fuffly, no se puede resistir a una dulce melodia..." -Rubeus Hagrid-','Desconocida','../../../assets/img/criatures/tags/fluffy.jpg',5),
                             (11,'Grapw','Grawp es un gigante que, a pesar de medir unos cinco metros, es bajito teniendo en cuenta los estándares de los gigantes. Es medio hermano materno de Rubeus Hagrid.','"¡HERMY!¿DONDE JAGI?¡GRAWP QUIERE JAGI!" -Grawp hablando a Hermione Granger-','Nac.1931','../../../assets/img/criatures/tags/grawp.jpg',44),
                             (12,'Norberta','Norberta, originalmente Norberto,  es una dragona ridgeback noruega criada por Rubeus Hagrid en su cabaña en el Colegio Hogwarts de Magia y Hechicería.','"a que es una preciosidad, eh fijaos chicos reconoce a su mami" -Rubeus Hagrid-','Nac. 24 de abril de 1992','../../../assets/img/criatures/tags/norberto.jpg',19),
                             (13,'Sra. Norris','La señora Norris es la gata mascota de Argus Filch, el conserje de Colegio Hogwarts de Magia y Hechicería. La señora Norris tiene una fuerte e inusual relación con su amo, al que le advierte si los estudiantes se comportan mal. Ella se describe y aparece casi de la misma manera que Filch, con ojos de color amarillo, cuerpo esquelético y flaco y piel del color de polvo.','"Mi gata...mi pobre gata, QUIEN HA HECHO ESTO...EXIJO UN CASTIGO PARA LOS CULPABLES" -Argus Filch-','Nac.1931','../../../assets/img/criatures/tags/señora-norris.jpg',33),
                             (14,'Scabbers','Pettigrew se escondió como Scabbers la rata, esperando evitar a los otros partidarios de Lord Voldemort. Como Voldemort se había encontrado con su caída en la información de Peter, los Mortífagos sospechaban que era un traidor. Buscando una familia mágica para llevarlo, entró en posesión de Percy Weasley y, más tarde, en el hermano menor de Percy Ron. Fue bien cuidado mientras vivía con los Weasley.\nEstaba claro que Scabbers era una rata extraordinaria; era inusualmente viejo para una rata de su especie, que tenía una esperanza de vida de tres años, sin embargo, la Familia Weasley lo tuvo por doce años. La razón por la que eligió ser adoptado por una familia de magos fue que podía estar al tanto de las noticias en el Mundo mágico y podía reunirse con su amo en caso de que regresara al poder. Posicionado como estaba, también podría traer a Harry Potter como un regalo de bienvenida, por lo que ningún Mortífago se atrevería a reclamarlo como un traidor, pero nunca tomó acción durante su tiempo como mascota de Ron, porque Voldemort no era fuerte lo suficiente para protegerlo. A pesar de una vez que mordió a Gregory Goyle en el nudillo cuando intentó robar la comida de Harry y Ron, Ron generalmente pensó que Scabbers era inútil, ya que todo lo que Scabbers hizo fue "comer y dormir". Sin embargo, Ron mostró su afecto por Scabbers cuando se enojó cuando pensó que Scabbers había sido comido por el gato de Hermione Granger, Crookshanks.',' "¡En una ocasión mordió a Goyle!¿Recuerdas, Harry?"','Nac. 1 de Septiembre de 1959','../../../assets/img/criatures/tags/scabbers.jpg',23),
                             (15,'Niffler','Newt Scamander era dueño de un escarbato al que llamaba Niffler, esté se escapó dos veces de su maleta durante su visita a Nueva York en 1926 e intentó robar tanto el Banco Nacional Steen como una joyería.  En 1927, el mismo escarbato produjo cuatro crías, cada una de un color diferente.\nSe sabe que Silvanus Kettleburn se quedó con 12 de escarbatos, incluso cuando habían destrozado su casa, su barco y su prótesis de pierna favorita.\nEl Hermano o hermana de Jacob podría tener uno en la Reserva de Criaturas Mágicas, y pidió prestado el escarbato hembra de Patricia Rakepick para ayudarle a encontrar la tercera bóveda maldita. Se sabe que su escarbato se portaba muy bien.\nMérula Snyde agrandó un escarbato en el Campo de Entrenamiento de Quidditch usando el encantamiento de congestión, haciéndolo más peligroso.\nDurante el año escolar 1994-1995, Rubeus Hagrid los utilizó como parte de su clase de cuarto año de Cuidado de Criaturas Mágicas. Antes de la clase, escondió 100 monedas de oro leprechaun en la tierra delante de su cabaña. Le dio a cada estudiante un escarbato y prometió un premio a quien encontrara la mayor cantidad de oro. Ron Weasley le preguntó a Hagrid si los escarbatos eran comprables como animales de compañía, y con conocimiento, Hagrid le dijo que su madre no querría uno, ya que causaban destrozos en las casas, pero esto no fue un definitivo "no". Esto significa que hay una gran probabilidad de que los magos puedan adquirir escarbatos. Cuando Hagrid atrapó a Gregory Goyle embolsando el oro, le explicó que tratar de robarlo no tenía sentido, ya que el oro leprechaun no tiene valor, ya que desaparece después de unas horas. El escarbato de Ron encontró la mayor cantidad de oro, por lo que Hagrid lo recompensó con una gran barra de chocolate de Honeydukes.\n','"Dale a un escorbuto algo dorado, monedas e incluso joyas y perdera toda la compostura" Newt Scamander','Desconocido','../../../assets/img/criatures/tags/niffler.jpg',27),
                             (17,'Kreacher','Kreacher fue un elfo doméstico que sirvió a la Casa Black con fanática lealtad durante la mayor parte de su vida, hasta que fue legado a Harry Potter tras la muerte de Sirius Black en 1996.\nFue particularmente fanático a "su ama" Walburga Black, quien murió en 1985, pero cuyo retrato aún gritaba órdenes de la pared en el vestíbulo principal de la Casa Black. Después de la muerte de la Sra. Black, Kreacher dejó que la casa se desordenara, haciendo poca o ninguna limpieza.\nTambién fue muy leal a Regulus Black, y más tarde a Harry Potter por quien luchó en la Batalla de Hogwarts junto a muchos otros elfos domésticos. Kreacher sobrevivió a la batalla final de la Segunda Guerra Mágica; se desconoce qué le sucedió más tarde en la vida, aunque murió en algún momento después de que Albus Potter fuera a Hogwarts.','"¡Kreacher no insultará a Harry Potter delante de Dobby, no señor, o Dobby se encargará de cerrarle la boca a Kreacher!" Dobby','naci. 1351, muer. septiembre del 2017','../../../assets/img/criatures/tags/kreacher.jpg',26);
INSERT INTO creatures VALUES
                          (1,'Acromantula','../../../assets/img/criatures/Acromantula.jpg','"¿Arañas? ¿Por qué no podemos perseguir mariposas?" -Ron Weasley-','Las acromántulas fueron descubiertas en el año 1794. Se cree que fueron creadas por magos (siglos antes de que se aprobara la Prohibición de cría experimental) con el fin de que custodien tesoros, ya que es raro que una criatura mágica posea la habilidad de hablar el lenguaje humano por naturaleza.\nEn 1943 una colonia de acromántulas, liderada por Aragog, se estableció en el Bosque Prohibido de Hogwarts. Tras la muerte de su líder y el ascenso al poder de Voldemort, esta colonia pasó a ser leal al ejército del Señor Oscuro.','yes','xxxxx'),
                          (2,'Lechuza-Buho','../../../assets/img/criatures/lechuza.jpg','"La mejor tienda para conseguir una lechuza es El emporio de las lechuzas, nunca lo olvides Harry, no hay ninguna igual"  -Rubeus Hagrid-','Las lechuzas y los buhos son aves rapaces de patas largas, en las que se observan plumas que no llegan a cubrirlas por completo. Los ojos son negros y el pico de color claro. Las diferencias más remarcadas que se encuentran al distinguir las subespecies son los colores en el la parte frontal del cuerpo, con más o menos manchas. \nSon utilizadas por la gente magica, para el envio de correo en general.\n','no','xx'),
                          (3,'Basilisco','../../../assets/img/criatures/Basilisco.jpg','«De las muchas bestias pavorosas y monstruos terribles que vagan por nuestra tierra, no hay ninguna más sorprendente ni más letal que el basilisco, conocido como el rey de las serpientes. Esta serpiente, que puede alcanzar un tamaño gigantesco y cuya vida dura varios siglos, nace de un huevo de gallina empollado por un sapo. Sus métodos de matar son de lo más extraordinario, pues además de sus colmillos mortalmente venenosos, el basilisco mata con la mirada, y todos cuantos fijaren su vista en el brillo de sus ojos han de sufrir instantánea muerte. Las arañas huyen del basilisco, pues es éste su mortal enemigo, y el basilisco huye sólo del canto del gallo, que para él es mortal.»','El Basilisco es una serpiente gigante, también conocida como el Rey de las Serpientes, es una criatura criada por magos tenebrosos. El primer basilisco del que hay constancia fue criado por Herpo el Loco, un mago tenebroso de Grecia que hablaba pársel. Después de muchos experimentos, Herpo descubrió que de un huevo de gallina incubado por un sapo salía una serpiente gigantesca dotada de poderes extraordinariamente peligrosos.\nEs clasificado por el Ministerio de Magia con XXXXX, debido a que es asesino de magos y no puede ser domesticado debido a que está dotada de poderes extraordinariamente peligrosos. Al ser una serpiente puede ser controlada por un hablante de pársel, pero también depende de la relación que tenga el hablante con la serpiente puesto que Tom Ryddle era el único que podía controlar el basilisco de Salazar Slytherin, mientras que Harry Potter no tenía ningún control sobre él.','yes','xxxxx'),
                          (4,'Bola de Fuego','../../../assets/img/criatures/Bola-fuego.jpg','¡El Bola de Fuego Chino... Oooh! -Barty Crouch Sr. a Viktor Krum-','El bola de fuego chino es el único dragón oriental que existe y tiene un aspecto especialmente llamativo. De escamas suaves y escarlatas, tiene una hilera de astas doradas alrededor de la cara, un hocico chato y ojos sumamente protuberantes. El bola de fuego se ganó ese nombre por la llama con forma de hongo que sale de sus narinas cuando está enfadado. Pesa entre dos y cuatro toneladas, y la hembra es más grande que el macho. Los huevos son de un carmesí brillante moteado de amarillo dorado y las cáscaras, muy estimadas en la hechicería china. El bola de fuego es agresivo, pero más tolerante con sus congéneres que la mayoría de los dragones; algunas veces acepta compartir su territorio con otros dos bolas de fuego. Aunque puede comer casi todos los mamíferos que se conocen, prefiere cerdos y seres humanos.\nLos huevos en polvo del bola de fuego chino tienen usos que fueron descubiertos por Quong Po en el siglo XV o XVI.','yes','xxxxx'),
                          (5,'Cancerbero','../../../assets/img/criatures/Cancerbero.jpg','"¿Un perro de tres cabezas? ¿A quien se le ocurriría traer a esa bestia al colegio?" -Ron Weasley-','Los perros de tres cabezas son una bestia mágica muy rara. Una manera de controlarlo, consiste en tocar música, con la cual se quedará dormido. En Harry Potter y la piedra filosofal, este perro es usado como protector y vigilante de la piedra de la vida.','yes','xxxxx'),
                          (6,'Centauro','../../../assets/img/criatures/Centauro.jpg','"No tienen nada que hacer aquí, centauros, es asunto del Ministerio. Respeten la ley, son criaturas de intelecto semihumano." -Dolores Umbridge-','Un centauro es una criatura mágica nativa de Europa(Grecia, Gran Bretaña, Croacia) cuya cabeza, torso y brazos aparentemente humanos están unidos a un cuerpo de caballo. Según ellos, son su propia especie, y no son cualquier tipo de mestizo. A pesar de ser muy inteligentes, los centauros son clasificados como bestias por el Ministerio de Magia, ya que estaban descontentos por tener que compartir su estatus con arpías y vampiros.\nSon seres astrólogos, con mentes profundas. Saben mucho pero comparten poco, y no se puede tratar de obtener una respuesta directa de un centauro.','no','xxxxx'),
                          (7,'Cola Cuerno','../../../assets/img/criatures/Colacuerno.jpg','"Oh, no te preocupes Harry, son criaturas mal entendidas... Aunque tengo que admitir que ese Colacuerno Húngaro da miedo."','El Colacuerno húngaro es un dragón nativo de Hungría y se considera la raza más peligrosa entre los dragones. Tiene escamas negras, una cola con púas, y los cuernos de bronce que sobresalen de su cabeza. Tiene ojos amarillos con pupilas verticales. Su rugido es como un maullido y gritos chirriantes, y su llama puede llegar a unos quince metros. Las llamas de la respiración del Colacuerno pueden llegar a temperaturas extremamante altas, pudiendo calentar una piedra al rojo vivo en cuestión de segundos. El Colacuerno se alimenta de ganado vacuno, ovino y caprino. Sus huevos son de color cemento con cáscaras muy duras.\n','yes','xxxxx'),
                          (8,'Dementor','../../../assets/img/criatures/Dementor.jpg','"Los Dementores están entre las criaturas mas nauseabundas del mundo. Infestan los lugares mas oscuros y mas sucios. Disfrutan con la desesperación y la destrucción ajenas, se llevan la paz, la esperanza y la alegria de cuanto los rodea... Si alguien se acerca mucho a un Dementor, este le quitara hasta el ultimo sentimiento positivo y hasta el ultimo recuerdo dichoso. Si puede, el Dementor se alimentara de el hasta convertirlo en su semejante: un ser desalmado y maligno. Lo dejara sin otra cosa que las peores experiencias de su vida."','Los Dementores son seres horribles de gran estatura, cubiertos por una capa de color negro. Son temidos porque se alimentan de la felicidad y de los recuerdos alegres, dejando solo la tristeza y la desolación. Asimismo, cuando están cerca producen un gran frío un descenso en la temperatura. Sus caras están ocultas por una capucha que sólo se quitan al dar el famoso "Beso del Dementor ". En gran parte se asemejan a los seres humanos, ya que tienen cuerpos parecidos al de una persona, pero no tienen rostro definido pues donde se deberían de encontrar los ojos hay una especie de membrana y su boca es un orificio abierto, además de que son criaturas putrefactas y tienen la capacidad de volar.','yes','xxxxx'),
                          (9,'Demiguise','../../../assets/img/criatures/Demiguise.jpg','"Pacíficos, herbívoros parecidos a monos, con la capacidad de volverse invisibles cuando se sienten amenazados."','El Demiguise es una bestia mágica herbívora y pacífica que puede hacerse invisible y predecir el futuro, lo que hace que sea muy difícil de atrapar.','no','x'),
                          (10,'Diricawl','../../../assets/img/criatures/Diricawl.jpg','"Observa bien su comportamiento Harry..1, 2, 3 y desaparecio, donde? Nadie lo sabe" -Albus Dumbledore-','El diricawl es un ave incapaz de volar originaria de la isla Mauricio. Tiene plumaje esponjoso y cuerpo rechoncho. Posee la capacidad de desaparecer en un estallido de plumas y volver a aparecer en otro lugar cuando es amenazado. Los muggles sabían de la existencia del diricawl, aunque lo conocían como dodo. Al no saber de su habilidad de aparición, creyeron que los habían cazado hasta exterminarlos.\nLa Confederación Internacional de Magos considera apropiado no decirle a los muggles que los diricawls todavía existen, por miedo a que los sigan matando.','no','xx'),
                          (11,'Duendecillo','../../../assets/img/criatures/Doxy.jpg','"Los duendecillos eran de color azul eléctrico y medían sobre 20cm de altura, con rostros afilados y voces tan agudas... era como oír a un montón de periquitos discutiendo. En el instante en que había levantado la funda de mi barita, una de ellos se abalanzo contra mí." -Gilderoy Lockhart-','Los duendecillos de Cornualles, también conocidos simplemente como duendecillos, son unas pequeñas Criatura Mágica revoltosas y muy traviesas, de color azul brillante, a las que les encanta hacer trucos y bromas.','no','xx'),
                          (12,'Duende','../../../assets/img/criatures/Duende.jpg','"Hay una creencia entre algunos duendes, y los de Gringotts son quizás más propensos a eso, de que no se puede confiar en los magos en asuntos de oro y tesoros, pues los magos no respetan el concepto de propiedad de los duendes. Si quieres guardar algo de mucho valor, el mejor lugar es Gringotts."  -Hagrid-','Los duendes son una raza muy inteligente de pequeños humanoides con dedos y pies largos que coexisten con los magos y brujas. Su dieta consiste en carne, raíces y hongos. Los duendes hablan en un idioma conocido como duendigonza, y son buenos orfebres notables por su platería; incluso acuñan monedas como dinero mágico. Debido a sus habilidades con el dinero y las finanzas, controlan la economía mágica en gran medida y administran el banco mágico Gringotts.\n\nLos duendes tienen su tipo de magia y pueden hacer magia sin varita. Están representados por la Oficina de Coordinación de los Duendes del Departamento de Regulación y Control de las Criaturas Mágicas en el Ministerio de Magia. Muchos magos consideran que los duendes son inferiores, y creen tontamente que los duendes se sienten cómodos con ese arreglo.','no','x'),
                          (13,'Esfinge','../../../assets/img/criatures/Esfinge.jpg','"Tenía el cuerpo de un león: grandes patas con garras y una cola larga y amarillenta que terminaba en un mechón castaño. Su cabeza, sin embargo, era la de una mujer. Volvió sus ojos almendrados hacia Harry mientras se acercaba."','La esfinge es una criatura mágica natal de Egipto, tiene la cabeza de una mujer humana sobre el cuerpo de un león. Las esfinges son capaces de comunicarse con los humanos y son conocidas por su amor a los acertijos y enigmas. Cuando el Ministerio de Magia empezó a clasificar las criaturas mágicas, la esfinge fue establecida en la clasificación de Bestia en vez de la clasificación de Criatura debido a sus tendencias violentas.','yes','xxxxx'),
                          (14,'Fenix','../../../assets/img/criatures/Fenix.jpg','"La mayor parte del tiempo es realmente precioso, con sus plumas rojas y doradas. Fascinantes criaturas, los fénix. Pueden transportar cargas muy pesadas, sus lágrimas tienen poderes curativos y son mascotas muy fieles." -Albus Dumbledore-','El Fénix es un magnifico pájaro mágico de color escarlata del tamaño de un cisne con plumaje rojo y dorado, junto con un pico y garras dorados, ojos negros y una cola tan larga como la de un pavo real. Sus plumas escarlatas brillaban débilmente en la oscuridad, mientras que las doradas plumas de su cola estaban calientes al tacto.\nLos fénix generalmente anidan en los picos de las montañas y son herbívoros amigables reconocidos por no luchar. A medida que los fénix se acercan a su día ardiente, parecen un pavo a medio desplumar. Sus ojos se vuelven opacos, sus plumas comienzan a caerse y comienzan a hacer ruidos de arcadas. Poco tiempo después de que comiences dichos comportamientos el pájaro estallará repentantemente en llamas, solo para resurgir de las cenizas poco después. En varios días, volverá a crecer a tamaño completo. Gracias a esta habilidad, los fénix pueden vivir hasta una edad inmensa, quizás incluso para siempre.\nEs una forma corpórea posible y rara del Encantamiento Patronus, como el Patronus de Albus Dumbledore. En el vestíbulo del Magicongreso Único de la Sociedad Americana se encontraban cuatro estatuas doradas de fénix de cuarenta pies de altura.','no','xxxx'),
                          (15,'Galés verde común','../../../assets/img/criatures/Gales-verde.jpg','"Se cree que un Gales verde común joven fue el causante del Gran incendio de Londres en 1666" -Ron Weasly-','El galés verde común o simplemente Galés verde, es una de las diez especies de dragón del mundo mágico. Es de color verde, tiene un rugido muy caracteristico, incluso melodioso y lanza finos chorros de llamas por su boca. Es nativo de Gales, en donde se ha creado una reserva para protegerlo. Se alimenta de pequeños mamíferos como ovejas e intenta mantenerse a distancia de los seres humanos a no ser que sea provocado, por lo que se considera una de las razas menos peligrosas. Anida en las montañas mas altas, sus huevos son de color marrón terroso moteados de verde y son clasificados como Bienes No Comerciables de Clase A.','yes','xxxxx'),
                          (16,'Hipogrifo','../../../assets/img/criatures/Hipogrifo.jpg','"Lo primero que tenéis que saber de los hipogrifos es que son orgullosos. Se molestan con mucha facilidad. Nunca ofendáis a ninguno, porque podría ser lo último que hicierais." -Rubeus Hagrid-','Un hipogrifo es una criatura mágica que tiene las patas delanteras, las alas y la cabeza de un águila gigante y el cuerpo, las patas traseras y la cola de un caballo. Es muy similar a otra criatura mágica, el grifo, con la parte trasera del caballo reemplazando a la parte posterior del león.\nLa cría de hipogrifos elegantes es una carrera mágica establecida, con criadores conocidos, incluida la madre de Newton Scamander. Las imágenes de hipogrifos de fantasía a veces se colocan en calendarios.\nEl hipogrifo es una de las raras formas corpóreas del encantamiento Patronus.','no','xxxx'),
                          (17,'Hocicorto sueco','../../../assets/img/criatures/Hocicorto.jpg','"El hocicorto sueco es un atractivo dragón azul plateado cuya piel es buscada para la fabricación de guantes y escudos protectores. La llama que sale de sus fosas nasales es de un azul brillante y puede reducir la madera y los huesos a cenizas en cuestión de segundos. El hocico corto tiene menos asesinatos de humanos en su nombre que la mayoría de los dragones, aunque como prefiere vivir en áreas montañosas salvajes y deshabitadas, esto no es mucho para su mérito."','El hocicorto sueco, es una de las diez especies de dragones pura sangre. Nativo de Suecia [1] donde habita en zonas montañosas, salvajes y deshabitadas. Su piel es azul plateado muy atractivo que tiene una gran demanda para la creación de guantes y escudos protectores, lanza una llama azul brillante muy caliente, que en segundos puede convertir huesos y madera en cenizas. Es el dragón que menos muertes ha causado porque vive en lugares de poco acceso. Esta clasificado como XXXXX y sus huevos son Bienes No Comerciables de Clase A.','yes','xxxxx'),
                          (18,'Hombre lobo','../../../assets/img/criatures/Hombre-lobo.jpg','"Existe una poción contra la licantropía, sin embargo tiene un alto costo producirla, sin olvidarnos de su asqueroso sabor..." -Remus Lupin-','Un hombre o mujer lobo también conocido como licántropo/a, son personas que llevan consigo la enfermedad de la Licantropía. Tienen la capacidad de transformarse en un lobo en apariencia y naturaleza, al haber sido mordidas por un hombre lobo en su forma de lobo en el momento de la luna llena. El hombre lobo se transforma bajo la influencia de la luna llena.\nUna mezcla de plata en polvo y díctamo aplicada a un mordida fresca sellará la herida y permitirá que la víctima siga viviendo como un hombre lobo, aunque se cuentan historias trágicas de víctimas que suplican la muerte en lugar de convertirse en hombres lobo. La Poción Matalobos, inventada por Damocles , permite al hombre lobo mantener su mente humana durante la transformación.\nUn hombre lobo no puede elegir si transformarse o no y ya no recordará quiénes son y mataría incluso a su mejor amigo si tuviera la oportunidad una vez transformado.  A pesar de esto, son capaces de recordar todo lo que han experimentado durante su transformación al volver a su forma humana.','yes','xxxxx'),
                          (19,'Ridgeback Noruego','../../../assets/img/criatures/Ironbelly.jpg','"El Ridgeback puede producir chorros de fuego de hasta 3,560 grados Fahrenheit" -Charlei Weasley"','El Ridgeback Noruego es una raza bípeda, de color gris metálico, con una gran envergadura, largas garras y escamas ásperas. Es la raza más grande de dragón que alcanza hasta seis toneladas, y sus ojos son de color rojo intenso. A veces, los ojos del Ironbelly parecen ser del mismo color que el cuerpo debido a una escama de protección.','yes','xxxxx'),
                          (21,'Thestral','../../../assets/img/criatures/Thestral.jpg','"Los únicos que pueden ver a los thestrals son los que han visto la muerte." -Luna Lovegood-','Un thestral es una variedad de caballo alado con un cuerpo esquelético, rostro de rasgos reptilianos y unas alas de aspecto curtido que recuerdan a las de un murciélago. Son nativos de las islas británicas e Irlanda, aunque se han visto en partes de Francia y la Península Ibérica. Son muy raros y están considerados como criaturas peligrosas por el Ministerio británico de magia.[5] Son inmerecidamente conocidos como augurio de desgracia y agresión por muchos magos, debido a que sólo son visibles por aquellos que han visto la muerte (y entendido plenamente el concepto), y a su apariencia lúgubre, demacrada y fantasmal.Debido a su clasificación XXXX, sólo los magos más experimentados deberían tratar de manejar éstas criaturas. Criarlas, así como poseerlas, puede ser desaconsejado o incluso ilegalizado sin la aprobación del Ministerio, de hecho, los magos que viven en áreas no protegidas contra los muggles están obligados por ley a realizar Encantamientos desilusiónadores en sus Thestrals con regularidad. Un thestral es también una posible forma corpórea del hechizo Patronus.','no','xx'),
                          (22,'Troll','../../../assets/img/criatures/Troll.jpg','"Wingardium leviosa..."','El Troll es una criatura temible de aproximadamente tres metros y medio de altura y pesa más de una tonelada. De él se destacan tanto su fuerza como su estupidez: ambas son prodigiosas; a menudo, es violento e impredecible, un poco como los gigantes. Los troles surgieron de Escandinavia, pero en la actualidad los podemos encontrar en el Gran Bretaña, Irlanda y otras zonas del norte de Europa.\nPor lo común, los troles conversan mediante unos gruñidos que parecen constituir un lenguaje primitivo, aunque algunos entienden e incluso hablan pocas y simples palabras de lenguas humanas. Los más inteligentes fueron entrenados como guardianes.\n\nHay tres clases de troles: de montaña, de bosque y de río. El trol de montaña es el más grande y maligno. carece de pelo y su piel es de un gris pálido. El trol de bosque tiene la piel de un verde o castaño, fino y desgreñado. El trol de río tiene cuernos cortos y puede ser peludo. Tiene una piel purpúrea y suele acechar debajo de puentes. Los troles comen carne cruda y prácticamente les da igual de donde salga; no le hacen ascos a nada, cazan desde animales salvajes hasta personas.','yes','xxxxx'),
                          (23,'Rata','../../../assets/img/criatures/rata.jpg','"Ven aqui rata inmunda...no escaparas de nuevo viejo traidor" -Sirius Black-','Algunos estudiantes las usan como mascotas en Hogwarts.','no','x'),
                          (24,'Sapo','../../../assets/img/criatures/sapo.jpg','"Buaghh...¿Tu mascota es un sapo Neville?" -Hermione Granger-','Algunos estudiantes las usan como mascotas en Hogwarts.','no','x'),
                          (25,'Bowtruckle','../../../assets/img/criatures/bowtruckle.jpg','"Este dulce y tímido animal solo se alimenta de insectos" -Newt Scamander-','El bowtruckle es un guardián de árboles inmensamente difícil de detectar. Se puede encontrar en el oeste de Inglaterra, el sur de Alemania, y en algunos bosques escandinavos. Un Bowtruckle sirve como guardián de su árbol, que suele ser uno cuya madera sirve para fabricar varitas mágicas. Los dedos en forma de rama le sirven para arrancarle los ojos a un enemigo. Por lo general es una criatura pacífica, pero se vuelven violentos si alguien amenaza a su árbol, o incluso a sí mismo. Para poder talar un árbol en el que hay un Bowtruckle, es necesario distraerlo ofreciéndole cochinillas. Son expertos abriendo cerraduras.','no','xx'),
                          (26,'Elfo doméstico','../../../assets/img/criatures/elfo.jpg','"Un elfo solo será libre si recibe una prenda de ropa como regalo" -Lucius Malfoy-','Un elfo o elfina doméstico/a (también conocido como simplemente elfos) es una criatura mágica que es inmensamente devota y leal a la persona designada como su amo.\n\nLos elfos domésticos sirven a magos y brujas y generalmente se encuentran bajo el empleo de viejas familias de magos que residen en establecimientos elaborados, como mansiones, y deben hacer todo lo que sus amos mandan a menos que sean liberados. Un elfo doméstico solo puede ser liberado cuando su amo les entrega ropa.\n\nLos elfos domésticos tienen su propia marca de magia sin varita que, a pesar de su pequeño tamaño físico, es muy poderosa.\nLa mayoría de los elfos domésticos no soportan la idea de ser libres y, en ocasiones, son amenazados por sus amos con regalarles una prenda. A los elfos domésticos no les gusta la libertad porque los magos los han acostumbrado a vivir de ese modo. Una de las consecuencias más dramáticas para ellos, que se deriva precisamente de este trato que reciben de los magos, consiste en que, al ser vistos como esclavos por los magos, la mayoría de las familias de magos tienden a rechazar automáticamente a cualquier elfo doméstico que pretenda ser contratado a cambio de que se disminuya su condición de esclavitud, mediante prestaciones tales como una cierta remuneración o días libres cada cierto tiempo. La razón de que sea una consecuencia dramática para ellos consiste en que, debido a este innato rechazo por parte de los magos de que los elfos domésticos deseen no ser tratados como esclavos, los elfos domésticos que ya viven en esta condición saben que, si llegan a ser liberados debido a alguna falta, les será sumamente difícil lograr que otra familia de magos los contrate mientras insistan en exigir prestaciones que les permitan distanciar su condición laboral de la esclavitud, pudiendo pasar literalmente años sufriendo las consecuencias del desempleo. Esto llega al punto en que una gran mayoría de ellos (como Winky) se toman el hecho de ser liberados por sus amos mediante la entrega de una prenda por parte de los mismos, en los casos en que se juzga que han desobedecido por completo a sus amos, como una forma de humillarlos y ponerlos en vergüenza, a la vez que un doloroso castigo por sus faltas. A casi todos (con la excepción de Dobby) les indigna la idea de pedir una remuneración por los servicios que prestan a sus amos. Los elfos pueden ser liberados por sus amos. En caso de la muerte del amo, si el elfo es sirviente no sólo del difunto, sino de la familia, éste pasará a ser sirviente de la generación que le continúa a su amo original; en caso de que el perteneciente a la siguiente generación no quiera o no pueda mantenerlo como su sirviente, éste tendrá derecho a donarlo a otra persona.','no','xxxx'),
                          (27,'Escarbato','../../../assets/img/criatures/escarbato.jpg','El escarbato es una bestia del Reino Unido que tiene un sedoso pelaje negro y un hocico largo.','Los escarbatos son criaturas similares a roedores con un hocico largo similar al de un ornitorrinco y una capa sedosa y esponjosa de pelo. Nativos de Gran Bretaña, viven en madrigueras tan profundas de aproximadamente 6 metros bajo tierra, y las hembras producen de seis a ocho crías en una sola camada.\n\nLos escarbatos poseen una bolsa en sus vientres que puede transportar mucho más de lo que aparenta, como si de un encantamiento de extensión indetectable se tratase.\n\nSon criaturas apacibles y pueden ser afectuosas con sus dueños. Sin embargo, también pueden destruir sus pertenencias y propiedades en busca de cosas que brillan, y por esta razón no es aconsejable tenerlos como mascotas domésticas. También se da a entender que pueden volverse agresivos se los provocaban, ya que el segundo escarbato liberado en la oficina de Dolores Umbridge aparentemente trató de arrancarle un trozo de su pierna.','no','xxx'),
                          (28,'ZouWu','../../../assets/img/criatures/zouwu.jpg','"Es un zouwu, una criatura china. Son increíblemente rápidos e increíblemente poderosos. Pueden recorrer más de mil kilómetros en un día… y este podría llevarte de un extremo a otro de París de una zancada" -Newt Scamander-','El zouwu tiene "cinco colores" y se parecía a un "gato gigantesco del tamaño de un elefante". Es una bestia monstruosamente grande parecida a un felino con un cuerpo rayado, una melena desaliñada, cuatro colmillos que salen de su boca, garras largas y afiladas y una cola multicolor desproporcionadamente larga del tamaño de una pitón. Los zouwus son increíblemente poderosos y rápidos, capaces de viajar a más de 1,000 kilómetros en un día.\n\nLos zouwu tienen la capacidad de aparecerse como se demostró durante la fuga de Newt Scamander del Ministerio francés de la magia. Esta habilidad era lo suficientemente poderosa como para eludir la inmarcabilidad del ministerio de magia.','yes','xxxxx'),
                          (29,'Gente Acuatica','../../../assets/img/criatures/agua.jpg','"Las sirenas y los tritones tenían la piel cetrina y el pelo verde oscuro, largo y revuelto. Los ojos eran amarillos, del mismo color que sus dientes partidos, y llevaban alrededor del cuello unas gruesas cuerdas con guijarros ensartados. Le dirigieron a Harry sonrisas malévolas. Dos de aquellas criaturas, que enarbolaban una lanza, salieron de sus moradas para observarlo, mientras batían el agua con sus fuertes colas de pez plateadas."','La Gente del agua son unas criaturas mágicas con inteligencia semi-humana que viven en el fondo del agua. Hay gente del agua por todo el mundo, pero varían en apariencia casi tanto como los seres humanos. Sus prácticas y costumbres tienen un halo de misterio equiparable al que rodea a los centauros, aunque aquellos magos que han aprendido sirenio hablan de comunidades sumamente organizadas que varían de tamaño según el hábitat y que, en algunos casos, disponen de viviendas construidas con mucho esmero. También se sabe que domestican criaturas tales como grindylows e hipocampos.\n\nAl igual que los centauros, la gente del agua ha rechazado el estatus de seres en favor de la clasificación de bestias, ya que estaban en contra de compartir el estatus con arpías y vampiros.','yes','xxxx'),
                          (30,'Billywig','../../../assets/img/criatures/Billywig.jpg','"Sus alas inducen un estado de ánimo elevado" -Xenophilius Lovegood-','El billywig es un insecto nativo de Australia. Mide alrededor de media pulgada (1,27 cm) de largo y es de un vívido color azul zafiro. Al ser tan veloz, el billywig es rara vez visto por muggles, magos o brujas una vez que han sido picados.','yes','xxx'),
                          (31,'Chupacabra','../../../assets/img/criatures/chupacabra.jpg','"Obtiene su alimento al chupar la sangre de cabras y otros seres vivos" -Gender Grindewalt','El chupacabra es una bestia parte lagartija, parte humanoide nativa de las Américas.\nTiene seis patas, múltiples púas y varios dientes afilados. Tiene marcas azules con anillos rojos.','yes','xxxx'),
                          (32,'Erumpent','../../../assets/img/criatures/erumpent.jpg','"En algún momento, Xenophilius Lovegood adquirió un cuerno de erumpent y lo mantuvo en su casa, creyendo que pertenecía a un Snorkack de cuernos arrugados" -Rubeus Hagrid-','El erumpent es una bestia gris, de gran tamaño y poder, natural de África. Pesa más de una tonelada y, de lejos, puede confundirse con un rinoceronte. Tiene una piel gruesa que repele la mayoría de encantamientos y maleficios, un cuerno largo y puntiagudo sobre el hocico y una cola larga que parece una soga. Los erumpents sólo dan a luz una cría por cada parto.\n\nEsta bestia no ataca a menos que se le provoque exageradamente, pero, cuando lo hace, los resultados suelen ser catastróficos. El cuerno del erumpent puede atravesar cualquier cosa, desde la piel hasta el metal, y contiene un fluido mortal que provoca que todo lo que haya sido inyectado con él reaccione provocando una poderosa explosión. Según Hermione Granger, basta con que el cuerno y cualquier objeto, hechizo o ser vivo se rocen levemente para que se produzca este resultado.\n\nLos erumpents no son muy numerosos porque, durante la época de apareamiento, los machos se hacen estallar los unos a los otros a menudo. Los magos africanos tratan la especie con mucha prudencia. El cuerno, la cola y el fluido explosivo del erumpent son utilizados en pociones, aunque están clasificados como Materiales Comerciables de Clase B (Peligrosos y Sujetos a Control Estricto).','yes','xxxx'),
                          (33,'Gatos','../../../assets/img/criatures/gatos.jpg','"Maldito gato...me ha llenado toda la cama de su asqueroso pelo" -Ron Weasley-','Estos felinos son utilizados por muchos estudantes como mascotas en Hogwarts.','no','x'),
                          (34,'Graphorn','../../../assets/img/criatures/graphorn.jpg','"Sus cuernos son un ingrediente para pociones muy apreciado, que se utiliza en pociones como el antídoto contra los venenos infrecuentes" -Severus Snape-','El Graphorn es una criatura mágica agresiva y peligrosa, nativa de las montañas de Europa.\n\nEl Graphorn es grande y jorobado, con la piel grisácea/púrpura más dura que la de los dragones. Puede rechazar la mayoría de los hechizos, tiene dos cuernos de oro, y camina sobre cuatro grandes patas.','yes','xxxx'),
                          (35,'Inferius','../../../assets/img/criatures/agua.jpg','"El inferius es un cadáver reanimado mediante los hechizos de un mago tenebroso. No está vivo; el mago sólo lo utiliza como una marioneta para hacer lo que se le antoja. Un fantasma, como espero que todos sepáis a estas alturas, es la huella que deja un difunto en la tierra…" -Albus Dumbledore-','Los inferi, en singular inferius, son cadáveres de humanos que han sido poseídos mediante magia oscura para hacer con ellos lo que se le antoje a un mago tenebroso. Aunque no es común ver inferi, en la Primera Guerra Magica Lord Voldemort mató a tantas personas que hizo un ejército con ellos. Gellert Grindelwald intentó hacer un ejército de ellos con la Piedra de la Resurrección pero no pudo porque no la encontró. Albus Dumbledore y Harry Potter lucharon contra ellos para obtener un horrocrux de Lord Voldemort. No poseen ninguna habilidad mágica, si es uno solo no será problema vencerlo, pero siempre se encuentran juntos, lo cual es un enorme problema para quien o quienes deben evadirlos. La única debilidad conocida de los inferius es el calor y la luz, en el caso de los que habitan casi todo el tiempo en lugares oscuros y fríos, como los que custodiaban el Guardapelo de Salazar Slytherin en el lago subterráneo de la Cueva del Horrocrux; no obstante, cabe la posibilidad de que puedan acostumbrarse a la luz y el calor, si lo exige el cumplimiento de las órdenes del mago tenebroso que los utilice.\n\nFue la mascota oficial del equipo nacional haitiano de Quidditch en la Copa Mundial de Quidditch de 2014.','yes','xxxx'),
                          (36,'Nundu','../../../assets/img/criatures/nundu.jpg','"el Nundu nunca ha sido doblegado por menos de cien magos trabajando juntos" -Newt Scamander-','El Nundu es un mamífero gigante similar a un leopardo, y es nativo del este de África. Se mueve silenciosamente pese a su gran tamaño, y es considerado la criatura más peligrosa del mundo. Su aliento causa enfermedades tan virulentas que pueden aniquilar poblaciones enteras. El Nundu es extremadamente difícil de doblegar, y nunca ha sido dominado por menos de 100 magos capacitados bien coordinados. Comparado con los dragones usados en el Torneo de los Tres Magos, los cuales fueron doblegados por aproximadamente diez magos, la perspectiva de esta rara bestia llega a ser verdaderamente aterradora.\n\nEldon Elsrickle poseía un Nundu que recibió como cachorro durante su viaje a África con tal de evitar ser capturado por una serie de robos que cometió. Usó este Nundu para proteger su casa y el gran tesoro que había acumulado dentro de ella, obtenido de robar a otros residentes londinenses con ayuda de un nuevo encantamiento desbloqueador. Mantuvo al Nundu doblegado con un hechizo aturdidor diario mientras estaba en casa, y liberándole cuando se marchaba. Un día, sin embargo, cuando se dio cuenta que todas las casas en el pueblo estaban protegidas por un nuevo encantamiento anti-alohomora inventado por Blagdon Blay, estaba tan furioso al regresar a casa que se olvidó de aturdir a su Nundu, y fue rápidamente asesinado por la bestia.','yes','xxxxx'),
                          (37,'Occamy','../../../assets/img/criatures/occamy.jpg','"El Occamy se encuentra en Extremo Oriente y en la India. Es una criatura con plumas, dos patas, alas y cuerpo sinuoso; puede alcanzar una longitud de cuatro metros y medio. Se alimenta principalmente de ratas y pájaros, aunque de vez en cuando caza monos. El occamy es agresivo con todos los que se le acercan, en especial si percibe que son una amenaza para sus huevos, cuya cáscara está hecha de la más suave y pura plata" -Newt Scamander-','Es una criatura emplumada, de dos patas y cuerpo de serpiente con alas que pueden alcanzar hasta cuatro metros y medio de altura. El occamy es agresivo con todos los que se le acercan y se alimenta de insectos, ratas, pájaros y ocasionalmente monos. Es extremadamente protector con sus huevos, cuya cáscara está hecha de la más suave y pura plata. Se encuentra en el Lejano Oriente y la India.\n\nSe sabe que el Occamy es coranáptico, lo que significa que puede crecer o encoger mágicamente para adaptarse al espacio del que dispone en su entorno.\n\nEs una forma corpórea conocida, posible pero rara, del encantamiento Patronus.','yes','xxxx'),
                          (38,'Perros','../../../assets/img/criatures/perros.jpg','"El mejor amigo del hombre... incluso si mides mas de 3 metros como yo" -Rubeus Hagrid-','Animal de compañia fiel al hombre, guardian y protector de los terrenos de su dueño.','no','xx'),
                          (39,'Serpiente','../../../assets/img/criatures/serpiente.jpg','"Este niño habla con las serpientes, Dumbledore, ¿y todavía confías en él?" -Cornelius Fudge"','Una serpiente es un reptil largo, delgado y sin patas. Es el símbolo de la casa de Slytherin, y el mago tenebroso Lord Voldemort tiene una serpiente como mascota llamada Nagini. En el mundo mágico hay muchos tipos de serpientes, pero la más grande y peligrosa de todas ellas es el basilisco, también conocido como el Rey de las Serpientes. El hechizo Serpensortia crea una serpiente desde la varita ejecutora, mientras que Vipera Evanesca se deshace de ella.[1] El hechizo Fuego maligno crea fieros dragones y serpientes. La piel de un boomslang, un especie de serpiente, es un ingrediente de la poción multijugos. La marca de Voldemort, la Marca Tenebrosa, es una calavera con una serpiente saliendo de su boca. En 1991 durante una visita a un zoo, Harry Potter dejó libre accidentalmente a una boa constrictor ante su primo Dudley Dursley. En 1995, Harry Potter fue testigo, en un sueño, del ataque de la serpiente Nagini a Arthur Weasley.','yes','xxx'),
                          (40,'Swooping','../../../assets/img/criatures/Swooping.jpg','"Una criatura grande, parecida a una mariposa que emerge de un objeto pequeño, posiblemente un capullo" -Newt Scamander-','El mal acechado, también por su nombre en inglés Swooping Evil, es una criatura mágica alada de colores azul y verde. Luce como un cruce entre un reptil y una mariposa extremadamente grande. Cuando no está volando con sus alas claveteadas, el Swooping Evil se encoge dentro de un capullo.\n\nPuede ser peligroso, ya que puede alimentarse del cerebro de las personas, pero también demostraron ser capaces de repeler algunos hechizos al volar en su camino.\n\nSecretan un veneno que, diluido correctamente, puede ser usado para borrar malos recuerdos.','yes','xxxxx'),
                          (41,'Thunderbird','../../../assets/img/criatures/thunderbird.jpg','"El Ave del trueno es una bestia voladora que puede sentir el peligro y crear tormentas mientras vuela" -Newt Scamander-','El ave del trueno, también conocida como thunderbird, es una gran bestia aviar mágica nativa de América del Norte que se encuentra más comúnmente en Arizona en el suroeste de los Estados Unidos. Siendo un pariente cercano del Fénix, el ave del trueno tiene la habilidad de poder crear tormentas mientras vuela y es muy sensible al peligro, por lo cual puede predecir cuándo este va a suceder. Una casa en el Colegio Ilvermorny de Magia y Hechicería lleva el nombre de esta criatura en su honor.','no','xxxx'),
                          (42,'Gigantes','../../../assets/img/criatures/gigantes.jpg','"De modo que vamos a hacer algunas conjeturas, aunque no es difícil deducir lo que sucedió." -Albus Dumbledore"','Los Gigantes fueron una vez abundantes en todo el mundo, con al menos un centenar de tribus diferentes. Durante la Primera Guerra Mágica, se aliaron con Lord Voldemort y fueron responsables de algunas de las peores atrocidades de la guerra contra la comunidad muggle. Los aurores del Ministerio de Magia atacaron y mataron a muchos gigantes, y los obligaron a esconderse en regiones remotas del mundo. El resto de los Gigantes se retiraron a una remota región montañosa del norte de Europa, y se estrechan en áreas, como resultado, matándose unos a otros por los asuntos más triviales, o, a veces por nada, sino pura violencia, redujeron su número a alrededor de ochenta en total.','yes','xxxxx');
INSERT INTO object VALUES
                       (1,'Anillo de Sorvolo Gaunt','El anillo de Sorvolo Gaunt fue una reliquia de la Casa Gaunt ,descendientes de Salazar Slytherin y Cadmus Peverell. Es un anillo de oro insertado con una piedra negra -siendo en realidad la Piedra de la Resurrección, pero ni Sorvolo Gaunt ni Lord Voldemort eran conscientes de su existencia- grabado con lo que Sorvolo Gaunt llamó el escudo de armas de los Peverell (habiendo entrado en la familia de los Gaunt por una heredera de los Peverell, no de la familia Slytherin- que en realidad es el símbolo de las Reliquias de la Muerte. El anillo pasó a través de los Gaunt masculinos, de generación en generación, hasta que fue robado de Morfin Gaunt por Tom Ryddle mientras Tom incriminó a Morfin por los asesinatos de la familia Ryddle.\n\nMientras estaba en Hogwarts, Tom llevaba abiertamente el anillo. Más tarde hizo del anillo su segundo horrocrux. Tom no encantó el anillo de inmediato, ya que fue visto usándolo mientras le preguntaba a Horace Slughorn sobre los horrocruxes, como se ve a través de los recuerdos de Slughorn en el pensadero.\n\nEn 1996, Albus Dumbledore recuperó el anillo, destruyéndolo con la espada de Godric Gryffindor.','../../../assets/img/objects/Horocruxes/anillo.jpg',1,0,0,0,NULL),
                       (2,'Copa de Helga Hufflepuff','La copa de Hufflepuff fue un objeto mágico creado por Helga Hufflepuff, una de los cuatro fundadoros del Colegio Hogwarts de Magia y Hechicería. Era una pequeña copa de oro con dos asas finamente labradas con un tejón grabado en el costado y algunas joyas. El tejón es el símbolo de la casa Hufflepuff. La copa también tiene la dudosa distinción de ser el único objeto que se sabe que ha sido robado de una bóveda (específicamente la bóveda de la familia Lestrange) en el banco mágico Gringotts.','../../../assets/img/objects/Horocruxes/copa.jpg',1,0,0,0,NULL),
                       (3,'Diario de Tom Ryddle','El Diario de Tom Ryddle era un simple diario en blanco, que Tom Riddle transformó en un Horrocrux. El diario se convirtió en un Horrocrux en 1943, durante el sexto año de Ryddle en el Colegio Hogwarts de Magia y Hechicería. Fue el primer Horrocrux que hizo y fue usado como un arma.\n\nAntes de la primera derrota de Lord Voldemort en 1981, el diario fue pasado al mortífago Lucius Malfoy. En secreto, Malfoy mantuvo el diario antes de deslizarlo, inadvertidamente, en el caldero de útiles escolares de Ginny Weasley en Flourish y Blotts en 1992. El diario utilizó su influencia mágica para poseer y obligar a Ginny a reabrir la Cámara de los Secretos, pero fue destruido por Harry Potter en 1993 con un colmillo de basilisco.','../../../assets/img/objects/Horocruxes/diario.jpg',1,0,0,0,NULL),
                       (4,'Guardapelo Salazar Slytherin','El guardapelo de Salazar Slytherin era el tercer Horrocrux que Lord Voldemort seleccionó por dos razones: tenia un gran valor ya que le perteneció al mismísimo Salazar Slytherin y porque él pensaba que le pertenecía ya que el guardapelo y el anillo estuvieron en su familia por generaciones.\n\nOriginalmente perteneció a la Familia Gaunt. Luego de que su padre y su hermano fueron llevados a Azkaban, Merope Gaunt, madre de Voldemort, se lo llevó consigo junto a su padre muggle Tom Ryddle (quien estaba bajo los efectos de una Poción de Amor). Después de que ella decidió dejar de darle la poción, él los abandonó a ella y a su hijo, a punto de nacer, por lo cual terminó de caer en desgracia. Todavía embarazada, se lo vendió a Caractacus Burke para obtener un poco de dinero para sobrevivir. Hepzibah Smith lo compró por una fuerte cantidad de dinero en Borgin y Burkes. Años después fue robado por Voldemort en la misma visita en la que robó la Copa de Helga Hufflepuff.\n\nLo ocultó en una cueva lejana, bajo la protección de cientos de Inferi, y múltiples hechizos, como una puerta de entrada a la cueva que sólo se abría con sangre, y una barca que solo permitía pasar a un mago adulto, además para recuperarlo se debía vaciar el líquido del contenedor en que se hallaba sumergido el guardapelo, y para esto no había otra forma que bebérselo: era la Pócima de la Desesperación.\n\nKreacher, el elfo doméstico de la familia Black, fue el primero en beber la poción, para que Lord Voldemort pudiera esconder el guardapelo. Más tarde, Regulus Black robó el guardapelo original y lo reemplazó por uno falso. El último en beber la dañina poción fue Albus Dumbledore, quien en su búsqueda de los Horrocruxes decidió tomarla, solo para que luego Harry Potter se diera cuenta que no habían obtenido el original. El verdadero guardapelo, estuvo en la casa de los Black a manos de Kreacher, quien por muchos años fracasó en su intento por destruirlo (como le había indicado su amo Regulus Black), hasta que, tras la muerte de Sirius Black, Mundungus Fletcher lo robó, al igual que otras posesiones de los Black, para venderlo con fines completamente comerciales.\n\nA su vez, Fletcher fue chantajeado por Dolores Umbridge cuando se encontraba vendiendo parte de su botín, por lo que tuvo que darle el guardapelo a cambio de su silencio, y es Umbridge la última persona que lo posee antes de que Harry, Ron y Hermione se lo quiten en su infiltración en el Ministerio de Magia en 1997.\n\nFue destruido por Ron en el Bosque de Dean, donde Harry lo abrió hablándole en lengua pársel; luego de abrirse, el guardapelo torturó mentalmente a Ron con las imágenes de unos falsos Harry y Hermione Finalmente Ron lo destruyó con la espada de Godric Gryffindor.','../../../assets/img/objects/Horocruxes/guardapelo.jpg',1,0,0,0,NULL),
                       (5,'Diadema de Rowena Ravenclaw','La Diadema de Ravenclaw (también conocida como la Diadema perdida de Ravenclaw) fue la única reliquia conocida que perteneció a Rowena Ravenclaw, la fundadora de la Casa de Ravenclaw en el Colegio Hogwarts de Magia y Hechicería. Grabada en su superficie estaba la famosa cita de Ravenclaw: "Una inteligencia sin límites es el mayor tesoro de los hombres".\n\nSe dijo que realzaba la sabiduría de su portador, el atributo más preciado de la Casa de Ravenclaw. Tiene un zafiro azul con forma de óvalo. La diadema fue luego robada por su hija, Helena, un hecho que Rowena mantuvo en secreto desde los otros fundadores hasta su lecho de muerte.\n\nLa diadema de Rowena Ravenclaw, la Copa de Helga Hufflepuff y el Guardapelo de Salazar Slytherin, conformaron tres de los Horrocruxes de Lord Voldemort.','../../../assets/img/objects/Horocruxes/diadema.jpg',1,0,0,0,NULL),
                       (6,'Harry','El anillo de Sorvolo Gaunt fue una reliquia de la Casa Gaunt ,descendientes de Salazar Slytherin y Cadmus Peverell. Es un anillo de oro insertado con una piedra negra -siendo en realidad la Piedra de la Resurrección, pero ni Sorvolo Gaunt ni Lord Voldemort eran conscientes de su existencia- grabado con lo que Sorvolo Gaunt llamó el escudo de armas de los Peverell (habiendo entrado en la familia de los Gaunt por una heredera de los Peverell, no de la familia Slytherin- que en realidad es el símbolo de las Reliquias de la Muerte. El anillo pasó a través de los Gaunt masculinos, de generación en generación, hasta que fue robado de Morfin Gaunt por Tom Ryddle mientras Tom incriminó a Morfin por los asesinatos de la familia Ryddle.\n\nMientras estaba en Hogwarts, Tom llevaba abiertamente el anillo. Más tarde hizo del anillo su segundo horrocrux. Tom no encantó el anillo de inmediato, ya que fue visto usándolo mientras le preguntaba a Horace Slughorn sobre los horrocruxes, como se ve a través de los recuerdos de Slughorn en el pensadero.\n\nEn 1996, Albus Dumbledore recuperó el anillo, destruyéndolo con la espada de Godric Gryffindor.','../../../assets/img/objects/Horocruxes/harry.jpg',1,0,0,0,NULL),
                       (7,'Nagini','Voldemort tenía una relación especial con Nagini, ya que ella era su mascota y uno de sus Horrocruxes predilecto. Según Dumbledore, Voldemort tenía fuertes sentimientos por Nagini que no tenía por nadie más; ella era el único ser vivo que le había importado. Pudo comunicarse con Nagini como hablante de pársel y la convirtió en un Horrocrux en 1994, después de asesinar a Bertha Jorkins, lo que explicaba la inusual cantidad de control que tenía sobre ella. En 1997 y, probablemente antes de esa fecha, pudo comunicarse con ella en silencio y a través de grandes distancias, ya que ella pudo hacerle una señal cuando Harry Potter llegó al Valle de Godric. Esto puede deberse a su naturaleza como Horrocrux, lo que le dio un vínculo con Voldemort como el que poseía con Harry.\n\nVoldemort también pudo poseer a Nagini, lo que hizo en diciembre de 1995, durante el ataque a Arthur Weasley. En 1994, Peter Pettigrew ordeñó el veneno de Nagini para devolver a Voldemort a un cuerpo rudimentario y, como Horrocrux, su misma existencia contribuyó a mantener la inmortalidad de Voldemort. Si bien Voldemort era conocido por su independencia, que lo hace incapaz de sentir ningún tipo de apego o dependencia hacia los demás, el afecto que sentía por Nagini (y el hecho de que ella subraya su herencia con Salazar Slytherin) fue la razón principal por la que eligió convertirla en un recipiente que contenía un fragmento de su alma. Por supuesto, tener un lugar para mantener vivo a su maestro hizo que Nagini solo aumentara su valor a los ojos de Voldemort. Voldemort generalmente la enviaba a misiones, como infiltrarse en el Ministerio o retener a Harry Potter en Valle de Godric. Finalmente, Voldemort dejó de enviar a Nagini en misiones después de darse cuenta de que Harry sabía de la existencia de sus Horrocruxes y los estaba rastreando. La colocó dentro de una barrera para mantenerla a salvo tanto a ella como a su fragmento de alma, siempre y cuando creyera que ella ya no estaba bajo amenaza de ser asesinado por Harry. Voldemort se enfureció cuando Neville Longbottom decapitó a Nagini con la espada de Godric Gryffindor, e intentó matarlo en represalia. Nagini fue el último Horrocrux en ser destruido y su muerte llevó a la derrota final y a la muerte de Voldemort.','../../../assets/img/objects/Horocruxes/nagini.jpg',1,0,0,0,NULL),
                       (8,'Piedra filosofal','La Piedra de la Resurrección es una de las Reliquias de la muerte. De acuerdo con la leyenda, quien quiera que la uniese con la Varita de Saúco y la Capa de Invisibilidad, se convertiría en el Maestro de la Muerte. Fue creada o dada por la Muerte a Cadmus Peverell, el segundo de los hermanos Peverell, tenía el poder de traer a la gente de vuelta de la muerte, pero no de dejarlos como si nunca hubiesen muerto, claramente como espíritus definidos, no como personas vivas.\nLa leyenda establece que Cadmus Peverell, el primer propietario de la Piedra, la utilizó en un intento desesperado de traer a su amada de vuelta de la muerte, tuvo éxito pero solo consiguió que regresase en forma de espíritu el cual no pertenecía realmente al mundo de los vivos. Consciente de que no podría devolverla por completo a la vida Cadmus enloqueció, matándose a sí mismo para estar con ella.\nLa familia Peverell conservó la Piedra de la Resurrección, pasando de generación en generación, hasta que finalmente acabó en manos de Sorvolo Gaunt, un descendiente de los Peverell, en forma de Anillo. Aparentemente ni Sorvolo ni ninguno de sus parientes conocía la verdadera naturaleza del anillo ni del símbolo grabado en él. Sorvolo afirmó que el signo era el escudo de armas de los Peverell. En 1925, Sorvolo y su hijo Morfin fueron arrestados y enviados a Azkaban por atacar a muggles y por resistirse al arresto; la presión por el encarcelamiento y la subsecuente huída de su hija, Merope resultó ser demasiado para Sorvolo, y murió poco después de su liberación; legando el anillo a Morfin. En 1943, Tom Sorvolo Ryddle, quien sería el mago oscuro Lord Voldemort e hijo ilegítimo de Merope, robó el anillo a Morfin mientras estaba en Pequeño Hangleton y asesinó a su padre y abuelos. Morfin nunca se dio cuenta del robo de la piedra, su memoria fue bien modificada por Ryddle convenciéndole de que él había sido quien mató al padre y abuelos de Tom; pero lamentó la pérdida del anillo hasta el fin de sus días.','../../../assets/img/objects/reliquias/piedra-filosofal.jpg',0,1,0,0,NULL),
                       (9,'Varita de Sauco','No se sabe el nombre del hombre que mató a Antioch Peverell y se robó la varita, pero fue asesinado por Emeric el Malvado, un mago tenebroso, por la misma razón de la muerte de Antioch. Emeric murió a manos de Egbert el Ilustre, quien también tomó la varita para sí. A partir de entonces, la varita se perdió durante unos cien años, en los que el asesino de Egbert tuvo un duelo con el mago Godelot y este salió victorioso, obteniendo la maestría de la varita. Sin embargo, su hijo Hereward, que estaba loco, lo encerró en el sótano y lo asesinó sangrientamente, robándole la varita. Después de esto, la varita desapareció durante siglos, hasta que fue obtenida por Gregorovitch, un fabricante de varitas famoso. Este comenzó a alardear de poseerla y afirmaba estar buscando una forma de multiplicar su poder fabricando otra aún mejor. Esto probablemente fuera un simple truco para vender más varitas, pero era verdad que poseía la Varita de Saúco. Por ese tiempo, Gellert Grindelwald, mago tenebroso anterior a Lord Voldemort, tuvo un altercado con Gregorovitch y obtuvo la maestría de la varita con un pequeño encantamiento de desarme, ya que, al igual que todas las varitas, no era necesario matar al dueño para obtenerla. Albus Dumbledore la obtuvo después de resultar vencedor en su famoso duelo contra Grindelwald. Tras su muerte, Voldemort profanó su tumba, ya que buscaba una nueva varita al enterarse de la conexión entre su anterior varita y la de Harry Potter. Cuando el Señor Tenebroso secuestra a Ollivander, el fabricante de varitas, y le pregunta por qué no pudo matar a Harry en el cementerio de Pequeño Hangleton éste le habló sobre la conexión de núcleos centrales gemelos de las varitas de Voldemort y Harry, ya que las dos tenían una pluma del mismo fénix. Ollivander le dijo a Voldemort que para solucionar ese problema debía tomar prestada otra varita.\n\nLord Voldemort le pide su varita a Lucius Malfoy, pero cuando el Señor Oscuro intenta asesinar a Harry en su traslado desde el número 4 de Privet Drive hasta la casa de los padres de Tonks, la varita de Harry actúa por sí sola y ataca a Voldemort, rompiendo la varita de Lucius. Entonces Voldemort decide buscar no una varita nueva, sino una varita vieja, viejísima. Éste se entera a través de Ollivander, al que le aplica el maleficio Cruciatus, que Gregorovitch, otro fabricante de varitas (que le vendió la varita a Viktor Krum), alardeaba de tener la Varita de Saúco y había tratado de multiplicar sus poderes. Voldemort busca a Gregorovitch, pero éste le dice que le fue robada hace muchos años, y Voldemort, sin creerle, entra en su mente y ve la imagen de un joven risueño que escapa por una ventana al tiempo que Gregorovitch le lanzaba un encantamiento aturdidor. El Señor Tenebroso busca ansiosamente la identidad del ladrón, hasta que a Harry, en la pelea con Nagini en el Valle de Godric, se le cae una foto de éste. Voldemort, quien encuentra la foto, se da cuenta que el ladrón era Gellert Grindelwald, un mago tenebroso al que Dumbledore venció en 1945. Busca a Grindelwald en la torre más alta de Nurmengard, cárcel que el mismo Grindelwald había hecho construir para encarcelar a todo aquel que se le opusiera, y en la entrada de la cual se leía: "Por el Bien Mayor".\n\nGrindelwald le dice que nunca la tuvo, en su último intento de redención por el mal que causó en el pasado. Pero Voldemort, conocedor del duelo entre Grindelwald y Dumbledore, lo asesina. A continuación, Voldemort viaja a Hogwarts, donde, sin indicarle al director Severus Snape sus intenciones, profana la tumba de Albus Dumbledore, donde yace enterrada la Varita de Saúco, y se apodera de la misma.\n\nDurante la Batalla de Hogwarts, Voldemort asesina a Snape pensando que la varita no le funcionaba como debía, puesto que pasó a pertenecer a Severus por haber matado a Dumbledore. Sin embargo, mató a la persona equivocada, ya que Draco Malfoy había desarmado a Albus Dumbledore antes que Snape lo asesinara en la Torre de Astronomía, convirtiéndose Draco, sin saberlo, en su dueño. Cuando Harry fue capturado por los Carroñeros y llevado a la mansión Malfoy junto con Ron y Hermione, Harry logra vencer a Malfoy, sin imaginarse que por esto la Varita de Saúco (en ese momento estaba en manos de Albus Dumbledore dentro de su tumba) lo reconoció como su nuevo dueño, lo cual Harry dedujo luego.\n\nAl intentar Voldemort, en su enfrentamiento final con Harry, lanzarle la maldición asesina Avada Kedavra, la Varita de Saúco, incapaz de atacar a su dueño legítimo, rebota contra el mismo Voldemort, quitándole la vida. Harry tras el duelo, decide reparar su antigua Varita de acebo y pluma de Fénix, y le asegura al retrato de Dumbledore, en su despacho, que devolverá la Varita de Saúco a su tumba.','../../../assets/img/objects/reliquias/varita-sauco.jpg',0,1,1,0,NULL),
                       (10,'Capa Invisibilidad','Una capa de invisibilidad es una prenda mágica que hace invisible lo que cubre. Además de Harry Potter, Alastor Moody es el único conocido que posee dos capas invisibles, pero estas no son como la que posee Harry, ya que estas son capas invisibles comunes, en cambio la de Harry no pierde sus poderes con los años.\nLa capa de Harry fue pasada desde Ignotus Peverell, el primero que la poseyó, hasta su padre James Potter. Fue utilizada por Harry Potter una innumerable cantidad de veces a lo largo de su curso en Hogwarts y por Severus Snape para llegar a la casa de los gritos donde se encontraban Harry, Ron, Hermione, Sirius y Remus Lupin en 1994.[2] Dumbledore le devuelve la capa a Harry en su primer año en Hogwarts porque se la había pedido prestada a James Potter.\nLa Capa de Invisibilidad pasó al hijo de Ignotus. El hijo de Ignotus no tenía herederos varones, por lo que su hija mayor, Iolanthe, la heredó. La familia Peverell murió en la línea masculina en esta época, pero la reliquia se pasó de generación en generación a través de la línea femenina, los Potter, ya que Iolanthe se había casado con Hardwin Potter de Stinchcombe.\nEn el siglo XX, la Capa finalmente terminó en manos de Henry Potter, un miembro del Wizengamot, quien se la pasó a su hijo mayor Fleamont. Fleamont fue el padre de James Potter, el padre de Harry Potter. James usó la capa de invisibilidad en muchas de sus fechorías en el Colegio Hogwarts de Magia y Hechicería y la guardó después. Alrededor del tiempo en que Lord Voldemort estaba cazando a los Potter por su hijo, la Capa de Invisibilidad llamó la atención de Albus Dumbledore cuando James le mostró la Capa. Dumbledore, que había buscado las Reliquias de la Muerte en su juventud, pidió prestada la capa a James para estudiarla. Después de que James fue asesinado, la capa quedó en posesión de Dumbledore.\nDiez años después, Dumbledore le dio a Harry Potter la Capa de Invisibilidad como regalo de Navidad de forma anónima y le dijo que "la usara bien". Este sería un consejo que Harry usaría bastante bien durante su vida escolar y más allá, ya que la Capa de Invisibilidad ayudó a Harry en innumerables viajes y misiones, incluida su búsqueda de los Horrocruxes de Lord Voldemort. No fue hasta 1998, que Harry aprendió la verdadera naturaleza de su propia Capa y su verdadera identidad como la Capa de Invisibilidad, como se menciona en la leyenda de las Reliquias de la Muerte. Como último descendiente restante de Ignotus, la Capa era legítimamente de Harry y fue guardada por él después de la derrota de Lord Voldemort. Harry decidió pasárselo a sus hijos algún día, tal como lo habían hecho sus antepasados.','../../../assets/img/objects/reliquias/capa-invisibilidad.jpg',0,1,0,0,NULL),
                       (11,'Ajedrez Mágico','El ajedrez mágico es una variante magica del ya conocido ajedrez en el cual las piezas se mueven segun la orden del jugador.\nCuando una pieza es tomada, es destruida por la pieza atacante, aunque generalmente las piezas luchan entre ellas durante unos instantes. Aunque el combate entre ellas normalmente causa que se rompan en pedazos, esto no es demasiado importante dado que las piezas pueden repararse mediante magia. Los jugadores mueven sus piezas nombrándolas por su nombre y diciendo el cuadro al que desean que se mueva; según la numeracion del tablero.(por ejemplo: Caballo c3). En los libros, las piezas tienen consciencia de sí mismas al punto de confiar o desconfiar de la forma de jugar del jugador que las dirige, y aunque las reglas del juego las obligan a moverse hacia dónde el jugador que las controla les indique, constantemente tratan de dar consejos a este último sobre hacer su próximo movimiento, lo que puede resultar en que este gane o pierda si se deja guiar por estos consejos. Un claro ejemplo de esto se ve en el libro Harry Potter y la Piedra Filosofal, cuando, durante las vacaciones de Navidad, Harry trata de jugar contra Ron usando las piezas de Ajedrez de Seamus Finnigan, pero estas no confiaban en los movimientos que Harry hacía, de modo que trataron de darle consejos para jugar; en el libro no se dice si esto resultó en la victoria o en la derrota de Harry.\n\nDurante las Fiestas de Navidad, Harry Potter obtuvo su propio juego de ajedrez. El después lo rompió tras haber sido derrotado de nuevo por Ron Weasley.\nDurante 1992 un tablero gigante de ajedrez fue la tercera prueba de protección de la piedra filosofal. Usando sus muy avanzados conocimientos, Ron Weasley logró derrotarlo; con ayuda de sus amigos Harry Potter y Hermione Granger, a lo que por último se sacrificó al caballo negro (Ron Weasley) para que Harry pudiera hacer jaque mate al rey contrario.\n\nLas reglas del ajedrez mágico tiene las mismas reglas del ajedrez muggle.','../../../assets/img/objects/ajedrez-magico.jpg',0,0,0,1,NULL),
                       (12,'Autobús Noctámbulo','El Autobús Noctámbulo es un vehículo que transporta a magos. Tiene tres plantas, es de color morado y tiene escrito Autobús Noctámbulo en letras doradas sobre su parabrisas. Resulta invisible para los muggles. Harry se monta en él poco antes de su tercer año en Hogwarts. El conductor es Ernie (que ha demostrado tener una habilidad tal para conducirlo que puede ir a toda velocidad, esquivando los coches y autobuses por apenas centímetros), y el encargado, Stan Shumpike. El uniforme que viste el encargado es del mismo color del autobus: morado. De noche no hay otros asientos a bordo, sino que esta equipado con media docena de camas de latón por nivel. La iluminación viene de velas en candelabros que están en las paredes. Una pequeña escalera de madera lleva a los pisos superiores. Cuando es de día, se colocan sillas desiguales alrededor de las ventanas.\n\nEl autobús aparece si un mago o bruja lleva una maleta, saca su varita y realiza el hechizo Lumos.\n\nEl precio de un viaje desde Little Whinging a Londres es 11 sickles. Por 13 sickles recibes una taza de chocolate caliente y si pagas 15 sickles recibes una bolsa de agua caliente y un cepillo de dientes del color que escojas.\n\nVa a una increíble velocidad y las cosas como buzones, faros y demás se apartan de este como "por arte de magia". No obstante, hay que aclarar que, como se mueve dando giros y frenadas bruscas con frecuencia, los viajes en él pueden resultar turbulentos y muy incómodos para quienes no están acostumbrados a usarlo como medio de transporte.','../../../assets/img/objects/autobus-noc.jpg',0,0,0,1,NULL),
                       (13,'Cáliz de Fuego','El Cáliz de Fuego es el "juez imparcial" en el Torneo de los Tres Magos, que opta por qué estudiante representa a su respectivo colegio. Después de que los estudiantes hayan terminado de colocar su nombre en el cáliz, éste elige un estudiante de cada colegio, lanzando su nombre en un torrente de llamas rojas. Una vez elegidos, los participantes están sujetos a un contrato mágico, por el cual no puede retirarse del Torneo. Fue utilizado en el torneo de los tres magos, donde Albus Dumbledore creó una línea de edad alrededor de todo el cáliz durante el torneo, para evitar que los estudiantes con edades menores a diecisiete años puedan poner su nombre en el cáliz. Sin embargo, el cáliz fue engañado, al pensar que había más de tres colegios compitiendo, mediante un poderoso encanto Confundus realizado por Barty Crouch Jr., disfrazado de Alastor Moody. Esto hizo que en la selección haya un campeón cuarto, Harry Potter, junto a Cedric Diggory, Fleur Delacour y Viktor Krum. Las llamas del cáliz se apagaron y no se volverían a encender de nuevo hasta el próximo torneo. Más tarde se reveló que Crouch estaba trabajando para Lord Voldemort, como parte de un plan para utilizar la sangre de Harry para revivir al Señor Oscuro.','../../../assets/img/objects/caliz-fuego.jpg',0,0,0,1,NULL),
                       (14,'Vociferador','Una carta vociferadora es una carta mágica en un sobre rojo que tiene un mensaje grabado a un volumen de voz muy alto. En los libros se ha precisado que una carta vociferadora entrega su mensaje con una voz cuyo tono es cien veces superior a un tono de voz "normal".\n\nLa temperatura de las cartas vociferadoras comienza a aumentar rápidamente luego de la entrega, y explota si se deja sin abrir durante demasiado tiempo, provocando que el mensaje que contiene comience a vociferarse por sí solo. Este mecanismo garantiza que el destinatario abra la carta y, en última instancia, llegue a recibir su mensaje, cargado de toda la sensación de ira o disgusto que el remitente haya pretendido transmitirle, a pesar de que el destinatario sepa que contiene un mensaje desagradable en voz alta. En el fondo, está pensado para que dicho objetivo se cumpla, sin importar si el destinatario de la carta vociferadora decide abrirlo, dejarlo sin abrir, o incluso tratar de destruir el sobre, por ejemplo arrojándolo al fuego, ya que de ocurrir esto ultimo, sucederá exactamente lo mismo que si el destinatario de la carta vociferadora elige dejar sin abrir el sobre. Una vez que el mensaje ha sido recibido, el sobre estalla en llamas dejando sólo cenizas.\n\nEl propósito de la carta vociferadora es entregar un mensaje expresando ira o gran disgusto que la escritura estándar no puede expresar adecuadamente. A pesar de esto, se ha demostrado que son capaces de dirigirse a personas distintas al destinatario de la carta vociferadora en un tono totalmente diferente al que la carta deba emplear hacia el destinatario, si esa era la intención del remitente. Esto se demuestra en la película Harry Potter y la cámara secreta, en la escena en la que Ron recibe una carta vociferadora de su madre; cuando la carta termina de gritarle a Ron, se da la vuelta para hablarle a Ginny, diciéndole en un tono mucho más cordial que sus padres estaban orgullosos de ella por haber sido seleccionada en la casa Gryffindor.','../../../assets/img/objects/carta-vociferadora.jpg',0,0,0,1,NULL),
                       (15,'Desiluminador','El Desiluminador, también conocido como Apagador, es un dispositivo utilizado por Albus Dumbledore (el primer propietario y diseñador conocido del único Desiluminador que se sabe que existe) para retirar las fuentes de luz del entorno inmediato del Desiluminador, así como otorgarlas. Parece un encendedor de plata estándar.\n\nDumbledore dejó el Desiluminador a Ron Weasley, en su voluntad (presentada por Rufus Scrimgeour), después de su muerte.','../../../assets/img/objects/desiluminador.jpg',0,0,0,1,NULL),
                       (16,'Espada de Godric Gryffindor','La Espada de Godric Gryffindor es una espada mágica de mil años de antigüedad, hecha por los duendes, propiedad del famoso mago Godric Gryffindor, uno de los cuatro fundadores del Colegio Hogwarts de Magia y Hechicería.\n\nLa espada se usó más tarde en la búsqueda de Horrocruxes de Albus Dumbledore y Harry Potter, como una herramienta de destrucción contra los Horrocruxes, como un medio para hacer que Lord Voldemort volviera a ser mortal.','../../../assets/img/objects/espada.jpg',0,0,0,1,NULL),
                       (17,'Espejo de Oesed','El Espejo de Oesed (Erised en inglés) es un espejo, el cual, de acuerdo con Albus Dumbledore, muestra los "más profundos y más desesperados deseos de nuestro corazón". El nombre "Oesed" es "deseo" escrito de atrás hacia adelante, como se refleja en un espejo. La persona más feliz en el mundo se miraría en el espejo y vería su reflejo exactamente de la forma en que él o ella es. Inscrito en la parte superior está el siguiente texto: Oesed lenoz aro cut edon isara cut se onotse. Dando vuelta la inscripción y arreglando los espacios se produce: "Esto no es tu cara, sino de tu corazón el deseo".','../../../assets/img/objects/espejo.jpg',0,0,0,1,NULL),
                       (18,'Ford Anglia','El Ford Anglia volador es un pequeño 105E Ford Anglia azul modificado por Arthur Weasley. Lo encantó dándole la habilidad de volar, volverse invisible, que en su interior pudieran entrar cómodamente al menos 10 personas, 6 baúles, 2 lechuzas y una rata y para que nunca se le terminara el combustible, ya que todavía estaba allí meses después, cuando Harry y Ron entraron en el Bosque Prohibido.','../../../assets/img/objects/ford-anglia.jpg',0,0,0,1,NULL),
                       (19,'Galeón dorado','Un galeón o galeón de oro es la moneda de más valor del mundo mágico. Un galeón equivale a 17 sickles o 493 knuts y están hechos de oro.','../../../assets/img/objects/galeon.jpg',0,0,0,1,NULL),
                       (20,'Giratiempo','El giratiempo es un objeto mágico que permite retroceder en el tiempo. Tiene la apariencia de un reloj de arena pequeño y retrocede una hora por cada vuelta que le den. Es muy importante que el que usa un giratiempo evite el contacto con su ser pasado porque podrían atacarse, llegando incluso a quitarse la vida por la confusión, o peor aún, el usuario podría alterar (nunca se sabe si en forma leve o drástica) su propio futuro o el de las personas con quiénes haya interactuado, causando que el curso de su vida, la de los demás, o incluso el destino del mundo (o al menos el destino de una parte de él) vayan en una dirección completamente distinta a la que se conoce en una determinada línea de tiempo, siendo absolutamente imposible predecir no sólo cuál será esta nueva dirección, sino también hasta qué punto se producirá la desviación de la línea de tiempo original en dicha nueva dirección.\n\nSin embargo, para 2020, otros dos giratiempos fueros creados. El prototipo sólo dejaba al viajero en el pasado durante cinco minutos, mientras que el modelo mejorado permitía estar en el pasado durante el tiempo que se quisiera y volver al presente también cuando se quisiera.','../../../assets/img/objects/giratiempo.jpg',0,0,0,1,NULL),
                       (21,'Grageas Bertie Bott','Las Grageas Bertie Bott de todos los sabores (¡un peligro en cada bocado!) son un dulce muy popular en el mundo mágico creadas por Bertie Bott. Aunque su nombre no lo deja totalmente en claro, se caracterizan principalmente por ser grageas, literalmente, de "todos" los sabores, lo cual significa que entre las decenas de sabores que pueden llegar a tener están no sólo los sabores de cosas agradables, sino también los sabores de cosas desagradables, categoría dentro de la cual se comprenden no sólo sabores que pueden resultar desagradables o no desde el punto de vista culinario, según el gusto de cada persona, sino también sabores de sustancias o elementos que de las que, sin importar el gusto de quién las coma, casi cualquiera consideraría su consumo humano absolutamente impensable, imposible o por lo menos poco saludable o alimenticio; el ejemplo más claro de esto son sabores como el de cerilla de oído o moco. Esto las convierte en un dulce único, teniendo sabores desde fresa hasta vómito o cerilla. Se venden en cualquier lugar en el que se venda dulces como en Honeydukes o en el Expreso de Hogwarts. El profesor Dumbledore le contó a Harry Potter que en su juventud tuvo la mala suerte de probar una con gusto a vómito, y desde entonces habían dejado de gustarle. En otra ocasión, cuando estaba con Harry en la enfermería, comió una que sabía a cera de oído y casi se atragantó.','../../../assets/img/objects/grageas.jpg',0,0,0,1,NULL),
                       (23,'Mapa Merodeador','El Mapa del Merodeador es un documento mágico que revela todos los lugares del Colegio Hogwarts de Magia y Hechicería. No sólo se muestran todas las aulas, pasillos, y todos los rincones del castillo, sino que también muestra cada centímetro del terreno (excepto la Sala de los Menesteres), así como todos los pasajes secretos que se esconden dentro de sus muros y la ubicación de cada persona en el terreno, representada por un punto. También es capaz de identificar con precisión a cada persona, y no se deja engañar por animagos, pociones multijugos, o capas de invisibilidad, incluso los fantasmas de Hogwarts no están exentos de esto. También puede revelar pasajes secretos que Los Merodeadores han encontrado, aunque sólo lo hizo en una ocasión conocida (en su tercer año, Harry Potter muestra cómo utilizar la estatua de la bruja tuerta para entrar en la aldea de Hogsmeade).','../../../assets/img/objects/mapa.jpg',0,0,0,1,NULL),
                       (24,'Motocicleta voladora de Sirius Black','La motocicleta voladora de Sirius Black, es una motocicleta de apariencia muggle, ordinaria con sidecar, aunque las apariencias engañan, ya que es mucho más grande que su versión no mágica, produce mucho ruido y puede volar. Es lo suficientemente grande como para acomodar a Hagrid, un semi-gigante, y aun disponer de sitio para una persona de tamaño normal en su sidecar, puede volar tan rápido como para competir con una escoba voladora.','../../../assets/img/objects/moto.jpg',0,0,0,1,NULL),
                       (25,'Pensadero','El pensadero es un objeto mágico que sirve para revisar recuerdos, o en ciertos casos para despejar la mente (tal y como lo usaba Albus Dumbledore). Se parece a una pileta poco profunda de piedra decorada con runas y símbolos. Su interior está lleno de una sustancia de aspecto fluido/gaseoso tipo vaporoso, que almacena los recuerdos de las personas que los han introducido en él. Los recuerdos se visualizan como si formaras parte del mismo como espectador.','../../../assets/img/objects/pensadero.jpg',0,0,0,1,NULL),
                       (26,'Polvos Flu','Los Polvos Flu son unos polvos mágicos capaz de transportar a una persona de un lugar a otro mediante una Red Flu. Esta red conecta la mayoría de los hogares y edificios del mundo mágico. Estos polvos fueron inventados en el siglo XII por Ignatia Wildsmith.\n\nPara utilizarlos, hay que lanzar los polvos en el fuego de una chimenea, que se vuelve de un color verde esmeralda. Después entrar en la chimenea y decir de manera clara y alta el lugar al que deseas llegar. De no hacerlo, se puede acabar en un lugar equivocado. Por otro lado, durante el transporte mismo el usuario debe tener cuidado de mantener los codos pegados a los costados para reducir el riesgo de golpearse contra algo y/o desviarse del camino accidentalmente como resultado del golpe.\n\nUna forma alternativa de usar los Polvos Flu, empleada principalmente para permitir a un mago o bruja establecer comunicación directa con otros magos o brujas sin la necesidad de abandonar el lugar desde el que se usan los Polvos Flu, consiste en repetir el mismo procedimiento que se utiliza para trasladarse de un lugar a otro, pero metiendo únicamente la cabeza dentro de la chimenea, de forma que el resto del cuerpo del usuario permanece en el mismo sitio desde el que se usan los polvos; en este caso, sólo la cabeza es transportada de un lugar a otro pero sin afectar la funcionalidad del cuerpo del usuario, de este modo, gracias a los Polvos Flu, la cabeza del usuario puede entablar conversación con quienes se encuentren en el lugar de destino hablando desde la chimenea.\n\nEste tipo de transporte es mucho más rápido que las escobas, pero más lento que la Aparición. Sin embargo, a diferencia de la última, no se necesita una licencia para ser utilizada.\n\nSu proceso de fabricación, así como sus componentes, es desconocido, aunque nunca ha habido escasez. Estos datos están bien guardados por sus productores, y varias familias mágicas han intentado reproducirlas. Sin embargo, nunca han tenido éxito y muchos de ellos acaban en el hospital de San Mungo con heridas, donde se les hace referencia como caso de "polvos flu falsos".\n\nSu precio de venta es de dos Sickles por cucharada.','../../../assets/img/objects/polvos-flu.jpg',0,0,0,1,NULL),
                       (27,'Rana de chocolate','Las Ranas de Chocolate son un dulce muy común en el mundo mágico. Estas golosinas se pueden comprar en el carrito de los dulces del Expreso de Hogwarts y en Honeydukes. Los empaques son de color azul y dorado y tienen escritas las palabras "Rana de chocolate" en letras doradas además poseen una forma pentagonal. Cada uno de éstos contiene una rana de chocolate, que tratará de escaparse, y un cromo, con la imagen de alguna bruja o algún mago famoso, que se pueden coleccionar e intercambiar.','../../../assets/img/objects/rana.jpg',0,0,0,1,NULL),
                       (28,'Recordadora','Una Recordadora es una bola de cristal de tamaño de una pelota de tenis que contiene humo que se vuelve rojo cuando su dueño se ha olvidado de algo. El humo se vuelve a hacer claro una vez que lo que fue olvidado es recordado. Una de las principales limitaciones respecto a los beneficios que se obtienen usándola consiste en que, dado que la recordadora sólo es capaz de recordar a su usuario el hecho de que ha olvidado algo, más no exactamente qué es lo que el usuario ha olvidado (un favor pendiente, una tarea escolar, una celebración de algún tipo, etc) si la recordadora termina o no resultando útil para quien la usa, dependerá de si su usuario logra o no recordar qué es exactamente lo que ha olvidado.','../../../assets/img/objects/recordadora.jpg',0,0,0,1,NULL),
                       (29,'Expreso de Hogwarts','El Expreso de Hogwarts es el nombre del tren que circulaba entre el andén 9¾ de la estación King''s Cross en Londres y la estación de Hogsmeade. Hacía esto cerca de unas seis veces al año, tal vez más, según fuera necesario. El Expreso llevó diligentemente a los estudiantes hacia y desde el Colegio Hogwarts de Magia y Hechicería al comienzo y al final de cada período.\n\nEl tren salía de la plataforma 9¾ sin falta cada 1 de septiembre a las 11 de la mañana y llegaba a la estación de Hogsmeade a primera hora de la tarde. Algunos estudiantes tomaron el tren de regreso a la estación de King''s Cross para ir a casa durante las vacaciones de Navidad y Pascua, pero algunos no lo hicieron, ya que se quedaron en Hogwarts. También hizo el viaje de regreso a Londres al final del período en junio.','../../../assets/img/objects/tren.jpg',0,0,0,1,NULL),
                       (30,'Sombrero Seleccionador','El Sombrero Seleccionador tiene la misión de determinar a cuál de las cuatro casas (Gryffindor, Hufflepuff, Ravenclaw o Slytherin) debe pertenecer un nuevo estudiante al entrar en Hogwarts. Tiene más de diez siglos de antigüedad (perteneció a Godric Gryffindor), y un aspecto algo sucio, con muchos remiendos. La Ceremonia de Selección se celebra al inicio del banquete de comienzo de año, en el Gran Comedor de Hogwarts. Antes de la selección, el sombrero, que tiene una rasgadura similar a una boca ancha, canta una canción que él mismo compone y que siempre suele hablar sobre lo mismo; que las casas deben estar unidas aunque sean diferentes. A continuación del canto los alumnos de primer año van pasando alfabéticamente y se les coloca el sombrero en la cabeza. Tras unos momentos de deliberación, en los que puede también leer el pensamiento del alumno, anuncia su elección. En el segundo año, juega un papel muy importante, ya que Fawkes le lleva a Harry Potter la Espada de Gryffindor escondida en el sombrero.','../../../assets/img/objects/sombrero.jpg',0,0,0,1,NULL),
                       (32,'Varita de Bellatrix Lestrange','Fibra de corazón de dragón. Esta varita se describe como "inflexible"; Pasó a manos de Hermione Granger después de la escaramuza en la Mansión Malfoy en 1998.','../../../assets/img/objects/wanders/bellatrix.jpg',0,0,1,0,NULL),
                       (33,'Varita de Cedric Digory','Pelo de unicornio. Esta varita era "agradablemente flexible"; pelo de un unicornio macho particularmente fino (diecisiete palmos), que casi apuñala al Sr. Ollivander con su cuerno después de que arranca el pelo de la cola.','../../../assets/img/objects/wanders/cedric.jpg',0,0,1,0,NULL),
                       (34,'Varita de Dolores Umbridge','Fibra de corazón de dragón. Esta varita se describe como "inusualmente corta". Rota por el casco de un centauro en junio de 1996 en el bosque prohibido.','../../../assets/img/objects/wanders/dolores.jpg',0,0,1,0,NULL),
                       (35,'Varita de Draco Malfoy','Pelo de unicornio. Esta varita pasó a manos de Harry Potter después de la escaramuza en la Mansión Malfoy en 1998 hasta que Harry tomó posesión de la Varita de Saúco y reparó su primera varita.','../../../assets/img/objects/wanders/draco.jpg',0,0,1,0,NULL),
                       (36,'Varita de Fleur Delacour','Pelo de veela. En esta varita, el núcleo es un cabello de la abuela de Fleur, que era una veela.\nSegún Ollivander, las varitas con este núcleo son temperamentales.','../../../assets/img/objects/wanders/fleur.jpg',0,0,1,0,NULL),
                       (37,'Varita de Gilderoy Lockhart','Fibra de corazón de dragón. La varita fue descrita como costosa.','../../../assets/img/objects/wanders/gilderoy.jpg',0,0,1,0,NULL),
                       (38,'Varita de Harry Potter','La varita de Harry Potter mide veintiocho centímetros, y está hecha de acebo, con una pluma de fénix en su centro. Ésta fue donada por Fawkes, mascota de Albus Dumbledore. También la varita de Tom Sorvolo Ryddle alias Lord Voldemort posee una pluma del mismo fénix como núcleo, y se dice que Fawkes solo tenia una pluma más por lo que ambas son "gemelas". Es descrita como "bonita y flexible". ','../../../assets/img/objects/wanders/harry.jpg',0,0,1,0,NULL),
                       (39,'Varita de Hermione','La varita de Hermione Granger, estaba hecha de vid, con núcleo de fibra de corazón de dragón y medía 103/4 pulgadas (27,3 cm). Se caracterizaba por ser flexible y buena para realizar hechizos. La varita fue fabricada por Garrick Ollivander en algún momento antes de la educación de Hermione en Colegio Hogwarts de Magia y Hechiceria.','../../../assets/img/objects/wanders/hermione.jpg',0,0,1,0,NULL),
                       (40,'Varita de Lucius Malfoy','Fibra de corazón de dragón. Esta varita estaba guardada en un bastón con cabeza de serpiente que llevaba Lucius; "prestado" por Lord Voldemort y destruido por la varita de Harry Potter durante la Batalla de los siete Potters en 1997.','../../../assets/img/objects/wanders/lucius.jpg',0,0,1,0,NULL),
                       (41,'Varita de Minerva Mcgonagall','Fibra de corazón de dragón. Probablemente esta varita fue comprada por Minerva en Ollivanders a la edad de once años.','../../../assets/img/objects/wanders/minerva.jpg',0,0,1,0,NULL),
                       (42,'Varita de Neville Longbottom','Pelo de unicornio. Esta varita pudo haber sido una de las últimas de las varitas vendidas por el Sr. Ollivander antes de su desaparición en 1996.','../../../assets/img/objects/wanders/neville.jpg',0,0,1,0,NULL),
                       (43,'Varita de Peter Pettgrew','Fibra de corazón de dragón. Esta varita era de Pettigrew desde que Ollivander había sido secuestrado en 1996 ; pasó a manos de Ron Weasley después de la escaramuza en la Mansión Malfoy en 1998.','../../../assets/img/objects/wanders/peter.jpg',0,0,1,0,NULL),
                       (44,'Varita de Remus Lupin','Pelo de unicornio. Se dice que las varitas de ciprés están bien adaptadas a los magos que se sacrifican y están dispuestos a morir una muerte heroica. Lupin pasó la mayor parte de su vida solo para salvar a otros de tener que lidiar con las consecuencias de su aflicción, y murió defendiendo el castillo de Hogwarts en la Batalla de Hogwarts.','../../../assets/img/objects/wanders/remus.jpg',0,0,1,0,NULL),
                       (46,'Varita de Tom Riddle','La varita de Tom Ryddle medía 34 cm y cuarto de largo y pertenecía a Tom Ryddle. La varita estaba hecha de tejo, con un núcleo de pluma de fénix. Fue fabricada por Garrick Ollivander y era la "hermana" o "gemela" de la varita de Harry Potter ya que ambas compartían plumas de la misma ave. Esta varita fue el arma con el que Lord Voldemort asesinó a incontables personas, entre las cuales se incluyen James y Lily Potter, el Muggle Frank Bryce, la ex-empleada del Ministerio de Magia Bertha Jorkins y Amelia Bones. También, bajo las órdenes de Voldemort, Peter Pettigrew utilizó esta misma varita para matar a Cedric Diggory en 1995. Su forma se asemeja a la de un hueso.','../../../assets/img/objects/wanders/voldemort.jpg',0,0,1,0,NULL),
                       (47,'Varita de Ron Weasley','Sauce. Comprado con las ganancias de su padre en un sorteo del diario El Profeta. Arrebatada de él por carroñeros y reemplazada por la varita de Peter Pettigrew.','../../../assets/img/objects/wanders/ron.jpg',0,0,1,0,NULL),
                       (48,'Varita de Victor Krum','Fibra de corazón de dragón. Esta varita es más gruesa de lo normal y está hecha por Gregorovitch .','../../../assets/img/objects/wanders/victor.jpg',0,0,1,0,NULL),
                       (49,'Varita de Severus Snape','La varita de Severus Snape es la varita perteneciente al mismo, es de color negro y es usada para las ocasiones en las que su propietario hace hechizos que la requieran.','../../../assets/img/objects/wanders/snape.jpg',0,0,1,0,NULL),
                       (50,'Varita de Alastor Moody','La varita de Alastor Moody era de longitud, madera y núcleo desconocidos.','../../../assets/img/objects/wanders/alastor.jpg',0,0,1,0,NULL),
                       (51,'Varita de Cho Chang','Esta varita pertenece a la bruja Cho Chang. El núcleo, madera, flexibilidad y longitud son desconocidos.\n\nComo la mayoría de magos y brujas en Gran Bretaña, la adquirió probablemente a la edad de once años, en la tienda de Garrick Ollivander antes de comenzar su educación en el Colegio Hogwarts de Magia y Hechicería en 1990.','../../../assets/img/objects/wanders/cho.jpg',0,0,1,0,NULL),
                       (52,'Varitas hermanos Weasley','Se desconocen los detalles de estas varitas.','../../../assets/img/objects/wanders/gemelos.jpg',0,0,1,0,NULL),
                       (53,'Varita de Ginny Weasley','La Varita de Ginny Weasley está hecha de madera de Tejo con una longitud y núcleos desconocidos. La varita fue fabricada por Garrick Ollivander, en algún momento antes de que Ginny comenzara su educación en Colegio Hogwarts de Magia y Hechicería','../../../assets/img/objects/wanders/ginni.jpg',0,0,1,0,NULL),
                       (54,'Varita de Narcisa Malfoy','La varita de Narcisa Malfoy está compuesta por materiales desconocidos. Narcisa probablemente la compró alrededor de 1966 cuando tenía once años de edad en la Tienda de Varitas Ollivander en el Callejón Diagon la primera vez que asistió al Colegio Hogwarts de Magia y Hechicería.','../../../assets/img/objects/wanders/narcisa.jpg',0,0,1,0,NULL),
                       (55,'Varita de Nymphadora Tonks','La Varita de Nymphadora Tonks es de madera, longitud y núcleo desconocidos. La varita fue utilizada por la bruja y Metamorfomaga, Nymphadora Tonks.','../../../assets/img/objects/wanders/tonks.jpg',0,0,1,0,NULL),
                       (56,'Varita de Sirius Black','La varita de Sirius Black estaba hecha de roble, 28 cm, con núcleo de fibra de corazón de dragón. Puede que haya sido fabricada por Garrick Ollivander. Sirius Black pudo haber comprado esta varita en Ollivander a los once años al precio de siete galeones. Sirius la usó durante toda su estancia en Hogwarts hasta el momento en que murió en el departamento de misterios. Lo que le haya pasado a la varita luego de su muerte es desconocido. Puede que Harry Potter la haya dejado junto a todas sus pertenencias en el Número 12 de Grimmauld Place al cuidado de Kreacher.','../../../assets/img/objects/wanders/sirius.jpg',0,0,1,0,NULL),
                       (57,'Varita de Fenrir','Se desconocen los detalles de esta varita.','../../../assets/img/objects/wanders/fenrir.jpg',0,0,1,0,NULL),
                       (58,'Varita de Luna Lovegood','Es la segunda varita perteneciente a Luna Lovegood, después de que la primera fuese destruida por los mortífagos en 1997, cuando la secuestraron en el regreso a Hogwarts después de Navidad, porque Xenophilius Lovegood estaba escribiendo de más en El Quisquilloso (trataba temas como la defensa de Harry Potter, entre otros). La madera, núcleo, flexibilidad y longitud son desconocidos, pero se puede deducir que es parecida a la anterior, debido a que la varita elige al mago por su personalidad. Fue fabricada por Ollivander después de ser rescatado junto a Luna y Griphook de la Mansión Malfoy.','../../../assets/img/objects/wanders/luna.jpg',0,0,1,0,NULL),
                       (59,'Varita de Alecto Carrow','Esta varita pertenecía a Alecto Carrow.\n\nElla probablemente lo compró a los once años. Probablemente sea mantenido en almacenamiento o haya sido destruida cuando fue a Azkaban. Es muy probable que la haya utilizado en la Segunda Guerra Mágica. Su longitud, madera y núcleo son desconocidos.','../../../assets/img/objects/wanders/alecto.jpg',0,0,1,0,NULL),
                       (60,'Varita de Barty Crouch Jr.','Se desconocen los detalles de esta varita.','../../../assets/img/objects/wanders/crouch.jpg',0,0,1,0,NULL),
                       (61,'Varita de Albus Dumbledore','La varita de Albus Dumbledore era de una longitud, madera y núcleo desconocidos. Fue una de las varitas que usó antes de obtener la propiedad de la Varita de Saúco en 1945.','../../../assets/img/objects/wanders/albus.jpg',0,0,1,0,NULL),
                       (62,'Varita de Amycus Carrow','Esta varita pertenecía a Amycus Carrow.\n\nElla probablemente lo compró a los trece años. Probablemente sea mantenido en almacenamiento o haya sido destruida cuando fue a Azkaban. Es muy probable que la haya utilizado en la Segunda Guerra Mágica. Su longitud, madera y núcleo son desconocidos.','../../../assets/img/objects/wanders/amycus.jpg',0,0,1,0,NULL),
                       (63,'El Quisquilloso','El Quisquilloso es una revista de magos dirigida por Xenophilius Lovegood, el padre de Luna Lovegood. Su eslógan es "La voz alternativa para el Mundo de la Magia".\n\nQuisquilloso Formulario de suscripción\nFormulario de suscripción para el Quisquilloso.\n\nEs una publicación poco convencional, normalmente llena de artículos sobre criaturas mágicas cuya existencia no se ha demostrado (Blibbers maravillosos o Snorkack de cuernos arrugados), y de caricaturas de personajes famosos. Por este motivo, la mayoría de la comunidad mágica no toma en serio esta revista. Normalmente, su tirada es bastante reducida, siendo realizada en la casa de Lovegood mediante una imprenta mágica, como se muestra en el último libro de la saga. Sólo se dio un caso de número agotado, en el cual se tuvo que reeditar para hacer frente a la demanda: aquél que contenía la entrevista realizada por Rita Skeeter a Harry Potter. Esta entrevista fue luego adquirida por El Profeta cuando la vuelta de Lord Voldemort se hizo evidente para todos.','../../../assets/img/objects/quisquilloso.jpg',0,0,0,1,NULL),
                       (64,'Quaffle','Una de las pelotas del quidditch, de color rojo y no completamente esférica, es la que sirve para anotar puntos de 10 en 10 introduciéndola por uno de los 3 aros del equipo contrario. De ella se encargan los cazadores, los que anotan, y los guardianes, los que detienen los tantos.','../../../assets/img/objects/Quiddich/Quaffle.jpg',0,0,0,0,'1'),
                       (65,'Bludger','Pelota muy dura y negra que los golpeadores envían a los jugadores del equipo contrario para derribarlos.','../../../assets/img/objects/Quiddich/Bludger.jpg',0,0,0,0,'1'),
                       (66,'Snitch Dorada','La pelota más importante, dorada, rápida y muy pequeña. Su captura marca el final del partido y supone 150 puntos para el equipo cuyo buscador logre atraparla. En su proceso de creación se las embruja de tal modo que recuerde de por vida quien fue su captor.Antes se usaban Snitgets Dorados. También sirve para ocultar objetos dentro, como lo hizo Albus Dumbledore con el "anillo de la resurrección".','../../../assets/img/objects/Quiddich/Snitch.jpg',0,0,0,0,'1'),
                       (67,'Escobas Voladoras','Las escobas voladoras son un medio de trasnporte para muchos magos, sin embargo su pincipal uso es para la competición del Quiddich.','../../../assets/img/objects/Quiddich/Escoba.jpg',0,0,0,0,'1'),
                       (68,'Sickle de plata','Es la segunda moneda de más valor del mundo mágico, por debajo del galeón y por encima del knut. 1 Sickle equivale a 29 knuts; 17 Sickles hacen un galeón.','../../../assets/img/objects/sickle.jpg',0,0,0,1,'0');
INSERT INTO wizard VALUES
                       (1,'Harry Potter','Potter',1980,'../../../assets/img/wizards/harry.jpg','Estudiante - Miembro del ejercito de Dumbledore - Jefe de la oficina de Aurores','Daniel Radcliffe','Harry James Potter (n. el 31 de julio de 1980), es un mago de sangre mestiza y el único hijo de James y Lily Potter. Es la única persona conocida que ha sobrevivido a la maldición de Avada Kedavra...','../../../assets/img/wizards/harry-face.jpg','Gryffindor','red','Mestiza','Ciervo','Acebo, 27''94cm, flexible, pluma de fénix','0',0,0,1,0,10,38),
