                       (4,'Lucius Malfoy','Malfoy',1954,'../../../assets/img/wizards/lucius.jpg','Secuaz de Voldemort','Jason Isaacs','Lucius Malfoy, nacido en 1954, era un mago de sangre pura, hijo de Abraxas Malfoy...','../../../assets/img/wizards/lucius-face.jpg','Slytherin','green','Pura','Desconocido','Olmo, Nervio de Corazón de Dragón','0',1,0,0,0,NULL,40),
