                       (7,'James Potter','Potter',1960,'../../../assets/img/wizards/james.jpg','Estudiante - Auror','Adrian Rawlins','James Potter I (27 de marzo de 1960 - 31 de octubre de 1981) también conocido como Cornamenta, fue un mago de sangre pura...','../../../assets/img/wizards/james-face.jpg','Gryffindor','red','Pura','Ciervo','Caoba, 28.5 cm, flexible','0',0,0,1,0,NULL,NULL),
                       (8,'Albus Dumbledore','Dumbledore',1881,'../../../assets/img/wizards/albus.jpg','Director Hogwarts - Fundador de la Orden del Fenix','Michael Gambon','El profesor Albus Percival Wulfric Brian Dumbledore...','../../../assets/img/wizards/albus-face.jpg','Gryffindor','red','Mestizo','Fénix','38''1 cm, Saúco, núcleo de pelo de cola de Thestral','0',0,1,0,0,10,9),
                       (9,'Aberforth Dumbledore','Dumbledore',1883,'../../../assets/img/wizards/aberforth.jpg','Camarero del Cabezo de Puerco','Ciarán Hinds','Aberforth Dumbledore ( e. 1883/1884) es un mago mestizo, el segundo hijo de Percival y Kendra Dumbledore...','../../../assets/img/wizards/aberforth-face.jpg','Gryffindor','red','Mestizo','Desconocido','Desconocido','0',0,0,0,1,NULL,NULL),
                       (10,'Alastor Moody','Moody',1923,'../../../assets/img/wizards/alastor.jpg','Profesor - Auror - Miembro de la Orden del Fenix','Brendan Gleeson','Alastor Ojoloco Moody (f. 27 de julio de 1997) era un mago de Sangre Pura y líder de la Orden del Fénix...','../../../assets/img/wizards/alastor-face.jpg','Gryffindor','gray','Pura','Ave Rapaz','Desconocido','0',0,1,0,0,NULL,50),
                       (11,'Alecto Carrow','Carrow',1948,'../../../assets/img/wizards/alecto.jpg','Mortifago','Desconocido','Alecto Carrow es una bruja, hermana de Amycus Carrow y mortífaga...','../../../assets/img/wizards/alecto-face.jpg','Slytherin','green','Pura','Desconocido','Desconocido','0',1,0,0,0,NULL,59),
                       (12,'Neville Longbottom','Longbottom',1980,'../../../assets/img/wizards/neville.jpg','Estudiante - Miembro del ejercito de Dumbledore','matthew lewis','El profesor Neville Longbottom (n. 30 de julio de 1980) es el actual profesor de Herbología del Colegio Hogwarts...','../../../assets/img/wizards/neville-face.jpg','Gryffindor','red','Pura','No corpóreo','13 pulgadas, cerezo, pelo de unicornio','0',0,0,1,0,28,42),
                       (13,'Family Longbottom','Longbottom',1950,'../../../assets/img/wizards/Longbottom-family.jpg','Aurores - Mimbros de la Orden del Fenix','Desconocidos','Frank Longbottom fue un mago de Sangre pura esposo de Alice Longbottom y padre de Neville Longbottom...','../../../assets/img/wizards/Longbottom-family.jpg','Ravenclaw','blue','Pura','Desconocido','Desconocido','0',0,0,0,1,NULL,NULL),
                       (14,'Ron Weasley','Weasley',1980,'../../../assets/img/wizards/ron.jpg','Estudiante - Miembro del ejercito de Dumbledore - Auror','Rupper Grint','Ronald "Ron" Bilius Weasley (n. 1 de marzo de 1980) es un mago sangre pura, el sexto y más joven hijo de Arthur y Molly Weasley...','../../../assets/img/wizards/ron-face.jpg','Gryffindor','red','Pura','Jack Russell Terrier','Castaño, 23,4 cm, nervio de dragón','0',0,0,1,0,14,47),
                       (15,'Amos Diggory','Diggory',1939,'../../../assets/img/wizards/amos.jpg','Mago trabajador en Ministerio de Magia','Jeff Rawle','Amos Diggory fue un mago que trabajaba en el Departamento de Regulación y Control de Criaturas Mágicas en el Ministerio de Magia...','../../../assets/img/wizards/amos-face.jpg','Hufflepuff','yellow','Pura','Desconocido','','0',0,0,0,1,NULL,NULL),
                       (16,'Amycus Carrow','Carrow',1951,'../../../assets/img/wizards/amycus.jpg','Profesor Hogwarts - Mortifago','Ralph Ineson','El Profesor Amycus Carrow era un mago, hermano de Alecto Carrow y un Mortífago...','../../../assets/img/wizards/amycus-face.jpg','Slytherin','green','Pura','Desconocido','','0',1,0,0,0,NULL,62),
                       (17,'Angelina Johnson','Johnson',1977,'../../../assets/img/wizards/angelina.jpg','Estudiante - Miembro del ejercito de Dumbledore','Tiana Benjamin','Angelina Weasley (de soltera Johnson) (nacida en octubre de 1977) fue una bruja miembro del Ejército de Dumbledore...','../../../assets/img/wizards/angelina.jpg','Gryffindor','red','Mestiza','Desconocido','','0',0,0,1,0,NULL,NULL),
